-- Workout library: a static, curated pool of 55 workouts (11 categories x 5
-- variations), generated once from workout-library-specification.md and seeded
-- here — mirrors the coding_questions pattern (a global pool table, no
-- user_id, queried live by the deterministic rotation logic in
-- workout-core.ts). Not user-editable through the app.
create table if not exists workout_library (
  id text primary key,
  name text not null,
  category text not null,
  difficulty text not null,
  duration_minutes integer not null,
  estimated_calories integer not null,
  primary_muscles text[] not null default '{}',
  secondary_muscles text[] not null default '{}',
  equipment text[] not null default '{}',
  environment text not null,
  warmup jsonb not null default '[]',
  exercises jsonb not null default '[]',
  cardio jsonb,
  cooldown jsonb not null default '[]',
  coach_tips text[] not null default '{}',
  tags text[] not null default '{}',
  created_at timestamptz not null default now()
);

alter table workout_library enable row level security;
create policy "authenticated can read workout_library" on workout_library
  for select using (auth.role() = 'authenticated');

-- Per-user daily workout assignment. Unlike coding_daily_questions this is
-- NOT date-scoped for generation purposes — the rule is 'one active workout
-- at a time', not 'one per calendar day'. assigned_date is kept for history/
-- display purposes only.
create table if not exists daily_workouts (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users(id),
  workout_id text not null references workout_library(id),
  status text not null default 'pending' check (status in ('pending','in_progress','completed','skipped')),
  assigned_date date not null default current_date,
  completed_at timestamptz,
  task_id uuid references tasks(id) on delete set null,
  created_at timestamptz not null default now()
);
create index if not exists daily_workouts_user_status_idx on daily_workouts (user_id, status);

alter table daily_workouts enable row level security;
create policy "select own daily_workouts" on daily_workouts
  for select using (auth.uid() = user_id);
create policy "insert own daily_workouts" on daily_workouts
  for insert with check (auth.uid() = user_id);
create policy "update own daily_workouts" on daily_workouts
  for update using (auth.uid() = user_id);
create policy "delete own daily_workouts" on daily_workouts
  for delete using (auth.uid() = user_id);

-- Seed the 55-workout library
on conflict (id) do nothing;
