insert into workout_library (id, name, category, difficulty, duration_minutes, estimated_calories, primary_muscles, secondary_muscles, equipment, environment, warmup, exercises, cardio, cooldown, coach_tips, tags) values
('CHEST_TRICEPS_001', 'Chest & Triceps - Heavy Compound Focus', 'Chest & Triceps', 'Intermediate', 75, 560, ARRAY['Chest','Triceps']::text[], ARRAY['Shoulders','Core']::text[], ARRAY['Barbell','Bench','Dumbbells','Cables']::text[], 'Gym', '["5 min incline treadmill walk","Arm circles, 20 each direction","Band pull-aparts, 2x15","Push-ups, 2x10 (bodyweight, easy pace)"]'::jsonb, '[{"name":"Barbell Bench Press","sets":4,"reps":"6-8","rest":"120 sec","tempo":"2-1-1","rpe":8,"notes":"Heaviest lift of the day — go first while fresh. Retract shoulder blades before unracking."},{"name":"Incline Dumbbell Press","sets":4,"reps":"8-10","rest":"90 sec","tempo":"2-1-2","rpe":8,"notes":"30-45 degree bench. Control the negative, don''t bounce at the bottom."},{"name":"Weighted Dips","sets":3,"reps":"8-10","rest":"90 sec","tempo":"2-0-1","rpe":8,"notes":"Lean forward slightly for more chest emphasis. Add weight belt once bodyweight feels easy."},{"name":"Cable Chest Fly","sets":3,"reps":"12-15","rest":"60 sec","tempo":"2-1-1","rpe":7,"notes":"Squeeze at the midline for a full second."},{"name":"Close-Grip Bench Press","sets":3,"reps":"8-10","rest":"90 sec","tempo":"2-0-1","rpe":8,"notes":"Hands just inside shoulder width. Keep elbows tucked to protect the joint."},{"name":"Overhead Cable Triceps Extension","sets":3,"reps":"12-15","rest":"60 sec","tempo":"2-0-1","rpe":7,"notes":"Keep elbows fixed pointing forward, only the forearm moves."}]'::jsonb, '{"type":"Incline treadmill walking","duration":"15 min","intensity":"Moderate","targetHeartRateZone":"60-70% max HR"}'::jsonb, '["Doorway chest stretch, 30 sec each side","Overhead triceps stretch, 30 sec each side","Cross-body shoulder stretch, 30 sec each side"]'::jsonb, ARRAY['Breathe out on the push, in on the lower — never hold your breath under a heavy bar.','If your bench press stalls, drop the weight 10% and rebuild rather than grinding ugly reps.','At 108kg, joint stress on the shoulders adds up fast — stop a rep short of failure on pressing movements.']::text[], ARRAY['Fat Loss','Hypertrophy','Strength','Intermediate','Compound Focus','Free Weight']::text[]),
('CHEST_TRICEPS_002', 'Chest & Triceps - Upper Chest Emphasis', 'Chest & Triceps', 'Intermediate', 70, 540, ARRAY['Chest','Triceps']::text[], ARRAY['Shoulders','Core']::text[], ARRAY['Barbell','Bench','Machines','Cables']::text[], 'Gym', '["5 min rowing machine, easy pace","Scapular push-ups, 2x12","Band pull-aparts, 2x15","Empty-bar incline press, 1x12"]'::jsonb, '[{"name":"Incline Barbell Press","sets":4,"reps":"6-8","rest":"120 sec","tempo":"2-1-1","rpe":8,"notes":"30 degree incline max — steeper turns this into a shoulder press."},{"name":"Flat Dumbbell Press","sets":3,"reps":"8-10","rest":"90 sec","tempo":"2-1-2","rpe":8,"notes":"Full stretch at the bottom, press until arms are almost locked out."},{"name":"Machine Chest Press","sets":3,"reps":"10-12","rest":"75 sec","tempo":"2-0-1","rpe":7,"notes":"Good option to push closer to failure safely since the machine spots you."},{"name":"Low-to-High Cable Fly","sets":3,"reps":"12-15","rest":"60 sec","tempo":"2-1-1","rpe":7,"notes":"Targets the upper chest fibers specifically."},{"name":"Diamond Push-Ups","sets":3,"reps":"AMRAP","rest":"60 sec","tempo":"2-0-1","rpe":8,"notes":"Elbows close to the body. Stop 1-2 reps before form breaks down."},{"name":"Rope Triceps Pushdown","sets":3,"reps":"12-15","rest":"60 sec","tempo":"2-0-1","rpe":7,"notes":"Spread the rope apart at the bottom for a full contraction."}]'::jsonb, '{"type":"Rowing","duration":"12 min","intensity":"Moderate","targetHeartRateZone":"65-75% max HR"}'::jsonb, '["Doorway chest stretch, 30 sec each side","Standing triceps overhead stretch, 30 sec each side","Child''s pose, 45 sec"]'::jsonb, ARRAY['Upper chest is stubborn for most lifters — the incline angle matters more than the weight on the bar.','If your wrists ache on diamond push-ups, do them on dumbbell handles instead of flat on the floor.','Log your rowing pace each week — a faster 500m split at the same heart rate is real conditioning progress.']::text[], ARRAY['Fat Loss','Hypertrophy','Intermediate','Machine Based','Compound Focus']::text[]),
('CHEST_TRICEPS_003', 'Chest & Triceps - High Volume Pump', 'Chest & Triceps', 'Intermediate', 65, 520, ARRAY['Chest','Triceps']::text[], ARRAY['Shoulders']::text[], ARRAY['Dumbbells','Cables','Machines']::text[], 'Gym', '["5 min bike, easy pace","Push-ups, 2x12","Band pull-aparts, 2x15","Light dumbbell fly, 1x15"]'::jsonb, '[{"name":"Dumbbell Bench Press","sets":4,"reps":"10-12","rest":"75 sec","tempo":"2-1-2","rpe":8,"notes":"Lighter than your heavy day — this session is about total volume, not max weight."},{"name":"Incline Dumbbell Fly","sets":3,"reps":"12-15","rest":"60 sec","tempo":"2-1-2","rpe":7,"notes":"Slight bend in the elbow throughout, don''t let it turn into a press."},{"name":"Machine Chest Press","sets":3,"reps":"12-15","rest":"60 sec","tempo":"2-0-1","rpe":7,"notes":"Drop set on the final set — reduce weight 20% and continue to failure."},{"name":"Cable Crossover","sets":3,"reps":"15","rest":"45 sec","tempo":"1-1-2","rpe":7,"notes":"Cross hands over at the bottom for a longer squeeze."},{"name":"Dumbbell Skull Crushers","sets":3,"reps":"12-15","rest":"60 sec","tempo":"2-0-1","rpe":7,"notes":"Keep upper arms vertical, only the forearm swings."},{"name":"Cable Triceps Kickback","sets":3,"reps":"15","rest":"45 sec","tempo":"1-1-2","rpe":7,"notes":"Squeeze hard at full extension for a full second."}]'::jsonb, '{"type":"Cycling","duration":"10 min","intensity":"Light-Moderate","targetHeartRateZone":"60-65% max HR"}'::jsonb, '["Doorway chest stretch, 30 sec each side","Overhead triceps stretch, 30 sec each side"]'::jsonb, ARRAY['This is a pump day — chase the burn, not the weight on the dumbbells.','Rest periods are shorter here on purpose to keep the muscle under tension longer overall.','Good day to slot in after a heavier chest session earlier in the week.']::text[], ARRAY['Fat Loss','Hypertrophy','High Volume','Intermediate','Machine Based']::text[]),
('CHEST_TRICEPS_004', 'Chest & Triceps - Bodyweight & Dumbbell Hybrid', 'Chest & Triceps', 'Intermediate', 60, 500, ARRAY['Chest','Triceps']::text[], ARRAY['Shoulders','Core']::text[], ARRAY['Dumbbells','Bodyweight','Bench']::text[], 'Gym', '["5 min jump rope or brisk walk","Arm circles, 20 each direction","Incline push-ups, 2x10"]'::jsonb, '[{"name":"Standard Push-Ups","sets":4,"reps":"AMRAP","rest":"75 sec","tempo":"2-0-1","rpe":8,"notes":"Full range, chest to a fist''s height off the floor."},{"name":"Dumbbell Floor Press","sets":3,"reps":"10-12","rest":"75 sec","tempo":"2-1-2","rpe":7,"notes":"Great joint-friendly alternative to bench press — the floor limits range and protects the shoulder."},{"name":"Decline Push-Ups","sets":3,"reps":"10-12","rest":"60 sec","tempo":"2-0-1","rpe":8,"notes":"Feet elevated on a bench, targets upper chest."},{"name":"Dumbbell Pullover","sets":3,"reps":"12-15","rest":"60 sec","tempo":"3-1-2","rpe":6,"notes":"Light weight — this is about stretch and chest expansion, not load."},{"name":"Bench Dips","sets":3,"reps":"12-15","rest":"60 sec","tempo":"2-0-1","rpe":7,"notes":"Keep hips close to the bench to protect the shoulder joint."},{"name":"Close-Grip Push-Ups","sets":2,"reps":"AMRAP","rest":"60 sec","tempo":"2-0-1","rpe":8,"notes":"Finisher — hands under the chest, elbows tucked."}]'::jsonb, '{"type":"Elliptical","duration":"10 min","intensity":"Moderate","targetHeartRateZone":"65-75% max HR"}'::jsonb, '["Doorway chest stretch, 30 sec each side","Cross-body shoulder stretch, 30 sec each side"]'::jsonb, ARRAY['This session travels well — most of it works with just dumbbells and a bench.','Push-up volume adds up fast at 108kg — that''s a genuinely heavy load moving through the chest and triceps.','If AMRAP sets exceed 20 reps, add a weighted vest or slow the tempo instead of just doing more reps.']::text[], ARRAY['Fat Loss','Bodyweight','Intermediate','Free Weight','Compound Focus']::text[]),
('CHEST_TRICEPS_005', 'Chest & Triceps - Machine-Based Joint-Friendly', 'Chest & Triceps', 'Intermediate', 65, 510, ARRAY['Chest','Triceps']::text[], ARRAY['Shoulders']::text[], ARRAY['Machines','Cables']::text[], 'Gym', '["5 min incline treadmill walk","Band pull-aparts, 2x15","Machine chest press, 1x15 empty/light weight"]'::jsonb, '[{"name":"Machine Chest Press","sets":4,"reps":"10-12","rest":"90 sec","tempo":"2-1-2","rpe":8,"notes":"Fixed path takes stabilizer demand out of the equation — good for a lower-joint-stress heavy day."},{"name":"Pec Deck Fly","sets":3,"reps":"12-15","rest":"60 sec","tempo":"2-1-2","rpe":7,"notes":"Adjust seat so handles are at chest height at the start position."},{"name":"Incline Machine Press","sets":3,"reps":"10-12","rest":"75 sec","tempo":"2-1-2","rpe":7,"notes":"Upper chest focus without the stability demand of free weights."},{"name":"Cable Fly (Standing)","sets":3,"reps":"12-15","rest":"60 sec","tempo":"2-1-1","rpe":7,"notes":"Slight forward lean, squeeze hands together in front of the chest."},{"name":"Triceps Pushdown (Machine)","sets":3,"reps":"12-15","rest":"60 sec","tempo":"2-0-1","rpe":7,"notes":"Straight bar or rope, either works — pick whichever feels smoother on the elbow."},{"name":"Assisted Dip Machine","sets":3,"reps":"10-12","rest":"75 sec","tempo":"2-0-1","rpe":7,"notes":"Use just enough assistance to hit clean reps with good depth."}]'::jsonb, '{"type":"StairMaster","duration":"12 min","intensity":"Moderate","targetHeartRateZone":"65-75% max HR"}'::jsonb, '["Doorway chest stretch, 30 sec each side","Overhead triceps stretch, 30 sec each side"]'::jsonb, ARRAY['This is a good option on weeks where your shoulders or wrists feel beat up from barbell work.','Machines let you push closer to true failure safely — use that on the last set of each exercise.','Don''t skip this variation just because it''s ''easier'' on paper — the stimulus is just as real.']::text[], ARRAY['Fat Loss','Hypertrophy','Machine Based','Intermediate']::text[]),
('BACK_BICEPS_001', 'Back & Biceps - Heavy Pulling Focus', 'Back & Biceps', 'Intermediate', 75, 570, ARRAY['Back','Biceps']::text[], ARRAY['Rear Delts','Forearms','Core']::text[], ARRAY['Barbell','Pull-up Bar','Cables','Dumbbells']::text[], 'Gym', '["5 min rowing machine, easy pace","Band pull-aparts, 2x15","Scapular pull-ups, 2x8","Light lat pulldown, 1x15"]'::jsonb, '[{"name":"Deadlift","sets":4,"reps":"5-6","rest":"150 sec","tempo":"1-1-1","rpe":8,"notes":"Reset your brace between every rep. This is your heaviest lift — no ego reps."},{"name":"Weighted Pull-Ups","sets":4,"reps":"6-8","rest":"120 sec","tempo":"2-0-1","rpe":8,"notes":"Use assistance band if bodyweight x4 sets isn''t achievable yet — still counts."},{"name":"Barbell Bent-Over Row","sets":3,"reps":"8-10","rest":"90 sec","tempo":"2-1-1","rpe":8,"notes":"Hinge at the hips, flat back, pull to the lower ribs."},{"name":"Seated Cable Row","sets":3,"reps":"10-12","rest":"75 sec","tempo":"2-1-2","rpe":7,"notes":"Pull with the elbows, not the hands — think ''shoulder blades together''."},{"name":"Barbell Curl","sets":3,"reps":"8-10","rest":"60 sec","tempo":"2-0-2","rpe":7,"notes":"No swinging — if you need momentum, drop the weight."},{"name":"Hammer Curl","sets":3,"reps":"10-12","rest":"60 sec","tempo":"2-0-2","rpe":7,"notes":"Neutral grip, hits the brachialis and forearms."}]'::jsonb, '{"type":"Rowing","duration":"10 min","intensity":"Moderate","targetHeartRateZone":"65-75% max HR"}'::jsonb, '["Lat stretch on rack, 30 sec each side","Seated forward fold, 45 sec","Biceps wall stretch, 30 sec each side"]'::jsonb, ARRAY['Deadlifts are demanding on the CNS at your bodyweight — if grip fatigues first, use straps on the last 1-2 sets only.','Row variations should feel like your shoulder blades are doing the work, not your biceps.','Log your pull-up reps every session — this is one of the clearest strength markers as bodyweight comes down.']::text[], ARRAY['Fat Loss','Strength','Hypertrophy','Intermediate','Compound Focus','Free Weight']::text[]),
('BACK_BICEPS_002', 'Back & Biceps - Width & Thickness', 'Back & Biceps', 'Intermediate', 70, 550, ARRAY['Back','Biceps']::text[], ARRAY['Rear Delts','Forearms']::text[], ARRAY['Machines','Cables','Dumbbells']::text[], 'Gym', '["5 min bike, easy pace","Band pull-aparts, 2x15","Light lat pulldown, 2x12"]'::jsonb, '[{"name":"Lat Pulldown (Wide Grip)","sets":4,"reps":"8-10","rest":"90 sec","tempo":"2-1-2","rpe":8,"notes":"Pull to the collarbone, lean back slightly — no swinging the torso."},{"name":"T-Bar Row","sets":4,"reps":"8-10","rest":"90 sec","tempo":"2-1-1","rpe":8,"notes":"Chest supported if your gym has the pad — takes lower back load off."},{"name":"Single-Arm Dumbbell Row","sets":3,"reps":"10-12","rest":"75 sec","tempo":"2-1-2","rpe":7,"notes":"Brace on the bench, drive the elbow back and up toward the hip."},{"name":"Close-Grip Lat Pulldown","sets":3,"reps":"10-12","rest":"60 sec","tempo":"2-1-2","rpe":7,"notes":"V-bar handle, targets lower lat fibers."},{"name":"Incline Dumbbell Curl","sets":3,"reps":"10-12","rest":"60 sec","tempo":"2-0-2","rpe":7,"notes":"Full stretch at the bottom — this is the main benefit of the incline angle."},{"name":"Cable Curl","sets":2,"reps":"12-15","rest":"45 sec","tempo":"2-0-2","rpe":7,"notes":"Constant tension throughout, unlike free weights."}]'::jsonb, '{"type":"Assault Bike","duration":"8 min","intensity":"Moderate","targetHeartRateZone":"70-80% max HR"}'::jsonb, '["Lat stretch on rack, 30 sec each side","Cat-cow, 8 reps","Biceps wall stretch, 30 sec each side"]'::jsonb, ARRAY['Wide-grip work builds width, close-grip and rows build thickness — this session hits both.','Keep the assault bike interval fast but controlled — this is a conditioning finisher, not a max effort test.','Squeeze your shoulder blades together at the top of every row for a full second before releasing.']::text[], ARRAY['Fat Loss','Hypertrophy','Intermediate','Machine Based']::text[]),
('BACK_BICEPS_003', 'Back & Biceps - Dumbbell Only', 'Back & Biceps', 'Intermediate', 60, 510, ARRAY['Back','Biceps']::text[], ARRAY['Rear Delts','Core']::text[], ARRAY['Dumbbells','Bench']::text[], 'Gym', '["5 min brisk walk or bike","Band pull-aparts, 2x15","Light dumbbell row, 1x15"]'::jsonb, '[{"name":"Dumbbell Bent-Over Row","sets":4,"reps":"10-12","rest":"75 sec","tempo":"2-1-1","rpe":8,"notes":"Flat back throughout, hinge from the hips."},{"name":"Single-Arm Dumbbell Row","sets":3,"reps":"10-12","rest":"60 sec","tempo":"2-1-2","rpe":7,"notes":"Full stretch at the bottom, drive the elbow high at the top."},{"name":"Renegade Row","sets":3,"reps":"8 each side","rest":"75 sec","tempo":"1-0-1","rpe":7,"notes":"Wide stance for stability, brace the core hard to resist rotation."},{"name":"Dumbbell Pullover","sets":3,"reps":"12-15","rest":"60 sec","tempo":"3-1-2","rpe":6,"notes":"Slow and controlled, feel the stretch through the lats."},{"name":"Dumbbell Curl","sets":3,"reps":"10-12","rest":"60 sec","tempo":"2-0-2","rpe":7,"notes":"Alternating or both arms together, either works."},{"name":"Concentration Curl","sets":2,"reps":"12 each side","rest":"45 sec","tempo":"2-0-2","rpe":7,"notes":"Elbow braced against the inner thigh, isolates the biceps peak."}]'::jsonb, '{"type":"Rowing","duration":"10 min","intensity":"Moderate","targetHeartRateZone":"65-75% max HR"}'::jsonb, '["Lat stretch on rack, 30 sec each side","Biceps wall stretch, 30 sec each side","Child''s pose, 45 sec"]'::jsonb, ARRAY['This is a great travel-friendly session — dumbbells and a bench cover the whole workout.','Renegade rows are a core exercise disguised as a back exercise — keep the hips level, don''t let them rock.','If your lower back fatigues before your lats do, drop the row weight and focus on the mind-muscle connection instead.']::text[], ARRAY['Fat Loss','Hypertrophy','Intermediate','Free Weight']::text[]),
('BACK_BICEPS_004', 'Back & Biceps - Pull-Up Progression', 'Back & Biceps', 'Intermediate', 65, 530, ARRAY['Back','Biceps']::text[], ARRAY['Forearms','Core']::text[], ARRAY['Pull-up Bar','Cables','Dumbbells']::text[], 'Gym', '["5 min rowing machine, easy pace","Dead hangs, 2x20 sec","Scapular pull-ups, 2x8"]'::jsonb, '[{"name":"Pull-Ups","sets":5,"reps":"AMRAP","rest":"90 sec","tempo":"2-0-1","rpe":8,"notes":"Track total reps across all 5 sets — that running total is your progress marker."},{"name":"Chin-Ups","sets":3,"reps":"6-8","rest":"90 sec","tempo":"2-0-1","rpe":8,"notes":"Underhand grip — noticeably more biceps involvement than the pull-up."},{"name":"Lat Pulldown","sets":3,"reps":"10-12","rest":"75 sec","tempo":"2-1-2","rpe":7,"notes":"Use this to keep pulling volume up once bodyweight sets fatigue you."},{"name":"Face Pull","sets":3,"reps":"15","rest":"60 sec","tempo":"2-1-1","rpe":6,"notes":"Rope at upper-face height, pull toward the forehead — great rear delt and posture work."},{"name":"EZ-Bar Curl","sets":3,"reps":"10-12","rest":"60 sec","tempo":"2-0-2","rpe":7,"notes":"The angled grip is easier on the wrists than a straight bar."},{"name":"Reverse Curl","sets":2,"reps":"12-15","rest":"45 sec","tempo":"2-0-2","rpe":6,"notes":"Overhand grip, builds forearm and grip strength for your pulling lifts."}]'::jsonb, '{"type":"Assault Bike","duration":"8 min","intensity":"Moderate-High","targetHeartRateZone":"70-80% max HR"}'::jsonb, '["Dead hang, 30 sec","Lat stretch on rack, 30 sec each side","Forearm stretch, 20 sec each side"]'::jsonb, ARRAY['At 108kg, every pull-up rep is a serious relative-strength achievement — bodyweight coming down will show up here fastest.','If AMRAP sets drop under 3 reps, switch to banded assistance for the remaining sets rather than grinding singles.','Face pulls are cheap insurance for shoulder health — don''t skip them even on a tight schedule.']::text[], ARRAY['Fat Loss','Strength','Intermediate','Compound Focus','Free Weight']::text[]),
('BACK_BICEPS_005', 'Back & Biceps - Machine Circuit', 'Back & Biceps', 'Intermediate', 60, 500, ARRAY['Back','Biceps']::text[], ARRAY['Rear Delts']::text[], ARRAY['Machines','Cables']::text[], 'Gym', '["5 min elliptical, easy pace","Band pull-aparts, 2x15","Light seated row, 1x15"]'::jsonb, '[{"name":"Seated Row Machine","sets":4,"reps":"10-12","rest":"75 sec","tempo":"2-1-2","rpe":8,"notes":"Chest against the pad, pull with the elbows past your ribs."},{"name":"Lat Pulldown Machine","sets":4,"reps":"10-12","rest":"75 sec","tempo":"2-1-2","rpe":7,"notes":"Alternate grip weekly between wide and close for balanced development."},{"name":"Machine Row (Single Arm)","sets":3,"reps":"10-12 each side","rest":"60 sec","tempo":"2-1-2","rpe":7,"notes":"Fixes any left/right imbalance that barbell rows can hide."},{"name":"Rear Delt Machine Fly","sets":3,"reps":"12-15","rest":"60 sec","tempo":"2-1-1","rpe":6,"notes":"Light weight, focus on squeezing the shoulder blades together."},{"name":"Cable Curl (Machine Handle)","sets":3,"reps":"12-15","rest":"60 sec","tempo":"2-0-2","rpe":7,"notes":"Constant tension throughout the whole rep, unlike a dumbbell curl."},{"name":"Preacher Curl Machine","sets":2,"reps":"12","rest":"45 sec","tempo":"2-0-2","rpe":7,"notes":"Pad locks the upper arm in place — pure biceps isolation."}]'::jsonb, '{"type":"Elliptical","duration":"10 min","intensity":"Moderate","targetHeartRateZone":"65-75% max HR"}'::jsonb, '["Lat stretch on rack, 30 sec each side","Biceps wall stretch, 30 sec each side"]'::jsonb, ARRAY['This is a lower-fatigue session — good to slot in the day after a heavy deadlift day.','Machines let you isolate left/right imbalances that barbell work can mask — pay attention if one side is noticeably weaker.','Still push these sets close to failure — ''machine day'' doesn''t mean ''easy day''.']::text[], ARRAY['Fat Loss','Hypertrophy','Machine Based','Intermediate']::text[]),
('LEGS_001', 'Legs - Heavy Squat Focus', 'Legs', 'Intermediate', 80, 620, ARRAY['Quadriceps','Glutes','Hamstrings']::text[], ARRAY['Calves','Core']::text[], ARRAY['Barbell','Machines','Dumbbells']::text[], 'Gym', '["5 min bike, easy pace","Bodyweight squats, 2x15","Walking lunges, 2x10 each leg","Leg swings, 10 each direction"]'::jsonb, '[{"name":"Barbell Back Squat","sets":4,"reps":"6-8","rest":"150 sec","tempo":"2-1-1","rpe":8,"notes":"Depth to at least parallel. At 108kg your knees will feel this — warm up thoroughly before the first working set."},{"name":"Romanian Deadlift","sets":3,"reps":"8-10","rest":"120 sec","tempo":"2-1-1","rpe":8,"notes":"Soft knee bend, hinge from the hips, feel the hamstring stretch."},{"name":"Leg Press","sets":3,"reps":"10-12","rest":"90 sec","tempo":"2-1-2","rpe":7,"notes":"Don''t lock the knees out hard at the top — keep slight bend to protect the joint."},{"name":"Walking Lunges","sets":3,"reps":"10 each leg","rest":"75 sec","tempo":"2-0-1","rpe":7,"notes":"Dumbbells in hand, torso upright, front knee tracks over the toes."},{"name":"Leg Curl (Machine)","sets":3,"reps":"12-15","rest":"60 sec","tempo":"2-1-2","rpe":7,"notes":"Slow negative — hamstrings are often the weak link in the chain."},{"name":"Standing Calf Raise","sets":3,"reps":"15-20","rest":"45 sec","tempo":"1-1-2","rpe":6,"notes":"Full stretch at the bottom, full contraction at the top."}]'::jsonb, '{"type":"Incline treadmill walking","duration":"10 min","intensity":"Light","targetHeartRateZone":"55-65% max HR"}'::jsonb, '["Standing quad stretch, 30 sec each side","Seated hamstring stretch, 30 sec each side","Pigeon pose, 30 sec each side"]'::jsonb, ARRAY['Squatting at 108kg puts real compressive load through the knees and lower back — never sacrifice depth or bar path for extra weight.','Leg day burns the most calories of any session in this library — fuel it properly beforehand.','If knees ache the next day, swap barbell back squat for leg press for a few weeks and reassess.']::text[], ARRAY['Fat Loss','Strength','Hypertrophy','Intermediate','Compound Focus','Free Weight']::text[]),
('LEGS_002', 'Legs - Posterior Chain Focus', 'Legs', 'Intermediate', 75, 590, ARRAY['Hamstrings','Glutes']::text[], ARRAY['Lower Back','Calves']::text[], ARRAY['Barbell','Dumbbells','Machines']::text[], 'Gym', '["5 min bike, easy pace","Glute bridges, 2x15","Leg swings, 10 each direction","Bodyweight Romanian deadlift, 2x10"]'::jsonb, '[{"name":"Conventional Deadlift","sets":4,"reps":"5-6","rest":"150 sec","tempo":"1-1-1","rpe":8,"notes":"Reset fully between reps — this is a posterior-chain-dominant session so make it count."},{"name":"Hip Thrust","sets":4,"reps":"8-10","rest":"90 sec","tempo":"2-1-1","rpe":8,"notes":"Barbell across the hips, pad underneath. Full lockout, squeeze glutes hard at the top."},{"name":"Leg Curl (Machine)","sets":3,"reps":"12-15","rest":"60 sec","tempo":"2-1-2","rpe":7,"notes":"Isolated hamstring work to complement the deadlift and hip thrust."},{"name":"Bulgarian Split Squat","sets":3,"reps":"8-10 each leg","rest":"90 sec","tempo":"2-0-1","rpe":8,"notes":"Rear foot elevated, most of the weight through the front heel."},{"name":"Cable Pull-Through","sets":3,"reps":"12-15","rest":"60 sec","tempo":"2-1-1","rpe":7,"notes":"Great teaching tool for the hip-hinge pattern with less spinal load than a deadlift."},{"name":"Seated Calf Raise","sets":3,"reps":"15-20","rest":"45 sec","tempo":"1-1-2","rpe":6,"notes":"Targets the soleus, complements the standing variation."}]'::jsonb, '{"type":"StairMaster","duration":"10 min","intensity":"Moderate","targetHeartRateZone":"65-75% max HR"}'::jsonb, '["Seated hamstring stretch, 30 sec each side","Figure-4 glute stretch, 30 sec each side","Child''s pose, 45 sec"]'::jsonb, ARRAY['Hip thrusts are one of the best glute-builders available — don''t rush the lockout, hold the squeeze.','Bulgarian split squats expose left/right imbalances fast — expect one leg to be noticeably harder.','Deadlift volume is intentionally lower here since hip thrust and split squats add plenty of posterior-chain fatigue on top.']::text[], ARRAY['Fat Loss','Strength','Hypertrophy','Intermediate','Compound Focus']::text[]),
('LEGS_003', 'Legs - Quad-Dominant Machine Session', 'Legs', 'Intermediate', 65, 540, ARRAY['Quadriceps']::text[], ARRAY['Glutes','Calves']::text[], ARRAY['Machines','Dumbbells']::text[], 'Gym', '["5 min bike, easy pace","Bodyweight squats, 2x15","Leg extension, 1x15 light weight"]'::jsonb, '[{"name":"Leg Press","sets":4,"reps":"10-12","rest":"90 sec","tempo":"2-1-2","rpe":8,"notes":"A joint-friendly way to load the quads heavily without the spinal demand of a squat."},{"name":"Hack Squat Machine","sets":3,"reps":"10-12","rest":"90 sec","tempo":"2-1-1","rpe":8,"notes":"Feet slightly forward on the platform for more quad emphasis."},{"name":"Leg Extension","sets":3,"reps":"12-15","rest":"60 sec","tempo":"2-1-2","rpe":7,"notes":"Pause and squeeze for a full second at the top of every rep."},{"name":"Goblet Squat","sets":3,"reps":"12-15","rest":"60 sec","tempo":"2-0-1","rpe":7,"notes":"Dumbbell held at the chest, great for reinforcing an upright torso."},{"name":"Walking Lunges","sets":2,"reps":"12 each leg","rest":"60 sec","tempo":"2-0-1","rpe":7,"notes":"Finisher — keep the pace controlled even as legs fatigue."},{"name":"Standing Calf Raise","sets":3,"reps":"15-20","rest":"45 sec","tempo":"1-1-2","rpe":6,"notes":"Full range of motion, don''t bounce."}]'::jsonb, '{"type":"Cycling","duration":"10 min","intensity":"Light-Moderate","targetHeartRateZone":"60-70% max HR"}'::jsonb, '["Standing quad stretch, 30 sec each side","Calf stretch on wall, 30 sec each side"]'::jsonb, ARRAY['Machine-based leg days are a good rotation option to keep knees fresh between heavier barbell squat sessions.','Leg press foot placement changes the emphasis — higher on the platform shifts more to glutes and hamstrings.','This session is genuinely tough despite being lower-impact — don''t underestimate it on the schedule.']::text[], ARRAY['Fat Loss','Hypertrophy','Machine Based','Intermediate']::text[]),
('LEGS_004', 'Legs - Unilateral Strength & Stability', 'Legs', 'Intermediate', 70, 560, ARRAY['Quadriceps','Glutes']::text[], ARRAY['Hamstrings','Core']::text[], ARRAY['Dumbbells','Bench']::text[], 'Gym', '["5 min bike, easy pace","Bodyweight lunges, 2x10 each leg","Single-leg balance hold, 2x20 sec each side"]'::jsonb, '[{"name":"Bulgarian Split Squat","sets":4,"reps":"8-10 each leg","rest":"90 sec","tempo":"2-0-1","rpe":8,"notes":"The main event today — expect real fatigue by the last set on each leg."},{"name":"Dumbbell Step-Up","sets":3,"reps":"10 each leg","rest":"75 sec","tempo":"2-0-1","rpe":7,"notes":"Use a bench roughly knee height, drive through the whole foot."},{"name":"Single-Leg Romanian Deadlift","sets":3,"reps":"10 each leg","rest":"75 sec","tempo":"2-1-1","rpe":7,"notes":"Light dumbbells, focus on balance and hip control over load."},{"name":"Lateral Lunge","sets":3,"reps":"10 each side","rest":"60 sec","tempo":"2-0-1","rpe":7,"notes":"Trains a movement pattern most gym programs skip entirely."},{"name":"Goblet Squat","sets":2,"reps":"15","rest":"60 sec","tempo":"2-0-1","rpe":6,"notes":"Bilateral finisher after all the single-leg work."},{"name":"Standing Calf Raise (Single Leg)","sets":2,"reps":"15 each leg","rest":"45 sec","tempo":"1-1-2","rpe":6,"notes":"Hold onto something for balance if needed."}]'::jsonb, '{"type":"Incline treadmill walking","duration":"10 min","intensity":"Light","targetHeartRateZone":"55-65% max HR"}'::jsonb, '["Standing quad stretch, 30 sec each side","Figure-4 glute stretch, 30 sec each side","Hip flexor stretch, 30 sec each side"]'::jsonb, ARRAY['Unilateral work exposes and fixes strength imbalances that bilateral squats and presses hide.','Balance will be the limiting factor before strength on some of these — that''s normal, it improves fast with practice.','This is a lighter-load, higher-control session — a good rotation choice the week after a heavy squat or deadlift day.']::text[], ARRAY['Fat Loss','Strength','Intermediate','Free Weight']::text[]),
('LEGS_005', 'Legs - Glute & Hamstring Isolation', 'Legs', 'Intermediate', 60, 500, ARRAY['Glutes','Hamstrings']::text[], ARRAY['Lower Back']::text[], ARRAY['Machines','Cables','Dumbbells']::text[], 'Gym', '["5 min bike, easy pace","Glute bridges, 2x15","Banded lateral walks, 2x10 each direction"]'::jsonb, '[{"name":"Hip Thrust (Machine or Barbell)","sets":4,"reps":"10-12","rest":"90 sec","tempo":"2-1-1","rpe":8,"notes":"Full lockout every rep, hold the squeeze at the top for a full second."},{"name":"Leg Curl (Machine)","sets":4,"reps":"12-15","rest":"60 sec","tempo":"2-1-2","rpe":7,"notes":"Slow, controlled negative — resist the urge to just drop the weight back down."},{"name":"Cable Kickback","sets":3,"reps":"12-15 each leg","rest":"60 sec","tempo":"2-1-1","rpe":6,"notes":"Ankle cuff attachment, squeeze the glute hard at the top of each rep."},{"name":"Romanian Deadlift (Dumbbell)","sets":3,"reps":"10-12","rest":"75 sec","tempo":"2-1-1","rpe":7,"notes":"Moderate weight, focus on the hamstring stretch at the bottom."},{"name":"Banded Lateral Walk","sets":3,"reps":"10 each direction","rest":"45 sec","tempo":"controlled","rpe":6,"notes":"Band above the knees, stay low the whole set — great glute-medius work."},{"name":"Glute Bridge (Bodyweight)","sets":2,"reps":"20","rest":"45 sec","tempo":"1-1-1","rpe":6,"notes":"Finisher, pure burn — squeeze at the top of every rep."}]'::jsonb, '{"type":"Elliptical","duration":"10 min","intensity":"Moderate","targetHeartRateZone":"65-75% max HR"}'::jsonb, '["Figure-4 glute stretch, 30 sec each side","Seated hamstring stretch, 30 sec each side"]'::jsonb, ARRAY['This session is lower-impact on the knees and spine than a squat/deadlift day — good for a recovery-conscious week.','Mind-muscle connection matters more here than the load on the bar — slow down and feel the target muscle work.','Banded lateral walks look easy and are not — keep tension on the band the entire set, don''t let your feet drift together.']::text[], ARRAY['Fat Loss','Hypertrophy','Machine Based','Intermediate']::text[]),
('SHOULDERS_001', 'Shoulders - Heavy Press Focus', 'Shoulders', 'Intermediate', 65, 500, ARRAY['Shoulders']::text[], ARRAY['Triceps','Traps','Core']::text[], ARRAY['Barbell','Dumbbells','Cables']::text[], 'Gym', '["5 min bike, easy pace","Arm circles, 20 each direction","Band pull-aparts, 2x15","Empty-bar overhead press, 1x12"]'::jsonb, '[{"name":"Standing Barbell Overhead Press","sets":4,"reps":"6-8","rest":"120 sec","tempo":"2-1-1","rpe":8,"notes":"Brace the core hard, don''t let the lower back arch to compensate."},{"name":"Seated Dumbbell Press","sets":3,"reps":"8-10","rest":"90 sec","tempo":"2-1-2","rpe":8,"notes":"Backrest supports the spine so you can push a little harder here than standing."},{"name":"Cable Lateral Raise","sets":3,"reps":"12-15 each side","rest":"60 sec","tempo":"2-1-1","rpe":7,"notes":"Constant tension beats dumbbells for this movement — lead with the elbow, not the hand."},{"name":"Rear Delt Fly (Cable or Dumbbell)","sets":3,"reps":"12-15","rest":"60 sec","tempo":"2-1-1","rpe":7,"notes":"Most neglected head of the shoulder — don''t skip it."},{"name":"Barbell Upright Row","sets":3,"reps":"10-12","rest":"75 sec","tempo":"2-1-1","rpe":7,"notes":"Wide grip reduces shoulder impingement risk versus a narrow grip."},{"name":"Front Plate Raise","sets":2,"reps":"12-15","rest":"60 sec","tempo":"2-1-1","rpe":6,"notes":"Light plate, controlled tempo — front delts get plenty of work from pressing already."}]'::jsonb, '{"type":"Rowing","duration":"10 min","intensity":"Moderate","targetHeartRateZone":"65-75% max HR"}'::jsonb, '["Cross-body shoulder stretch, 30 sec each side","Overhead triceps stretch, 30 sec each side","Doorway chest stretch, 30 sec each side"]'::jsonb, ARRAY['Overhead pressing is demanding on the lower back if you lean back to compensate — keep ribs down and glutes squeezed.','Lateral raises should never involve momentum — if you''re swinging the weight up, it''s too heavy.','Balance pressing volume with rear delt and upper back work every single session to protect shoulder health long-term.']::text[], ARRAY['Fat Loss','Strength','Hypertrophy','Intermediate','Compound Focus','Free Weight']::text[]),
('SHOULDERS_002', 'Shoulders - 3D Delt Development', 'Shoulders', 'Intermediate', 60, 480, ARRAY['Shoulders']::text[], ARRAY['Traps','Triceps']::text[], ARRAY['Dumbbells','Cables','Machines']::text[], 'Gym', '["5 min bike, easy pace","Arm circles, 20 each direction","Band pull-aparts, 2x15"]'::jsonb, '[{"name":"Machine Shoulder Press","sets":4,"reps":"8-10","rest":"90 sec","tempo":"2-1-2","rpe":8,"notes":"Fixed path is joint-friendly and lets you push closer to failure safely."},{"name":"Dumbbell Lateral Raise","sets":4,"reps":"12-15","rest":"60 sec","tempo":"2-1-1","rpe":7,"notes":"Slight bend in the elbows, raise to shoulder height — no higher."},{"name":"Cable Face Pull","sets":3,"reps":"15","rest":"60 sec","tempo":"2-1-1","rpe":6,"notes":"Pull to the forehead with elbows high — targets rear delts and upper back."},{"name":"Dumbbell Front Raise","sets":3,"reps":"12-15","rest":"60 sec","tempo":"2-1-1","rpe":6,"notes":"Alternate arms, control the descent."},{"name":"Reverse Pec Deck","sets":3,"reps":"12-15","rest":"60 sec","tempo":"2-1-1","rpe":6,"notes":"Rear delt isolation, squeeze the shoulder blades at the peak."},{"name":"Shrugs (Dumbbell)","sets":3,"reps":"12-15","rest":"60 sec","tempo":"1-1-1","rpe":6,"notes":"Straight up and down, no rolling the shoulders."}]'::jsonb, '{"type":"Cycling","duration":"10 min","intensity":"Light-Moderate","targetHeartRateZone":"60-70% max HR"}'::jsonb, '["Cross-body shoulder stretch, 30 sec each side","Neck stretch, 20 sec each side"]'::jsonb, ARRAY['''3D'' delts means training all three heads — front, side, and rear — every session, not just pressing.','This session prioritizes the side and rear delts, which are usually the most underdeveloped for lifters who only bench and press.','Shrugs should feel like straight-line elevation — resist the urge to roll the shoulders forward or back.']::text[], ARRAY['Fat Loss','Hypertrophy','Machine Based','Intermediate']::text[]),
('SHOULDERS_003', 'Shoulders - Push Press & Power', 'Shoulders', 'Intermediate', 60, 510, ARRAY['Shoulders']::text[], ARRAY['Triceps','Legs','Core']::text[], ARRAY['Barbell','Dumbbells','Kettlebell']::text[], 'Gym', '["5 min bike, easy pace","Bodyweight squats, 2x10","Arm circles, 20 each direction","Empty-bar push press, 1x8"]'::jsonb, '[{"name":"Push Press","sets":5,"reps":"5","rest":"120 sec","tempo":"explosive-1-1","rpe":8,"notes":"Small dip and drive with the legs to help launch the bar — this trains power, not just strength."},{"name":"Dumbbell Arnold Press","sets":3,"reps":"8-10","rest":"90 sec","tempo":"2-1-2","rpe":7,"notes":"The rotation hits the front and side delts through a longer range than a standard press."},{"name":"Kettlebell Overhead Carry","sets":3,"reps":"30 sec each side","rest":"60 sec","tempo":"walking","rpe":7,"notes":"Arm locked out overhead, walk slowly and controlled — huge shoulder stability builder."},{"name":"Cable Lateral Raise","sets":3,"reps":"12-15","rest":"60 sec","tempo":"2-1-1","rpe":7,"notes":"Constant tension complements the power work earlier in the session."},{"name":"Face Pull","sets":3,"reps":"15","rest":"60 sec","tempo":"2-1-1","rpe":6,"notes":"Non-negotiable after heavy pressing — keeps the rear delts and rotator cuff healthy."}]'::jsonb, '{"type":"Assault Bike","duration":"8 min","intensity":"Moderate-High","targetHeartRateZone":"70-80% max HR"}'::jsonb, '["Cross-body shoulder stretch, 30 sec each side","Overhead triceps stretch, 30 sec each side"]'::jsonb, ARRAY['Push press uses leg drive on purpose — it''s a different training stimulus than a strict press, not a shortcut.','Overhead carries look simple and expose weak stabilizers fast — start lighter than you think you need.','This session''s higher power output means you''ll want a longer rest between sets — don''t rush it.']::text[], ARRAY['Fat Loss','Strength','Conditioning','Intermediate','Compound Focus']::text[]),
('SHOULDERS_004', 'Shoulders - High Volume Isolation', 'Shoulders', 'Intermediate', 55, 450, ARRAY['Shoulders']::text[], ARRAY['Traps']::text[], ARRAY['Dumbbells','Cables']::text[], 'Gym', '["5 min bike, easy pace","Arm circles, 20 each direction","Band pull-aparts, 2x15"]'::jsonb, '[{"name":"Dumbbell Lateral Raise","sets":4,"reps":"15","rest":"45 sec","tempo":"2-1-1","rpe":7,"notes":"Light weight, chase the burn — this is a pump-focused session."},{"name":"Cable Front Raise","sets":3,"reps":"15","rest":"45 sec","tempo":"2-1-1","rpe":7,"notes":"Rope attachment, alternating arms."},{"name":"Bent-Over Dumbbell Rear Fly","sets":3,"reps":"15","rest":"45 sec","tempo":"2-1-1","rpe":7,"notes":"Hinge at the hips, flat back, small controlled arc."},{"name":"1.5 Rep Lateral Raise","sets":2,"reps":"10","rest":"45 sec","tempo":"2-1-2","rpe":7,"notes":"Full rep then half rep at the top counts as one — extra time under tension."},{"name":"Cable Y-Raise","sets":2,"reps":"15","rest":"45 sec","tempo":"2-1-1","rpe":6,"notes":"Arms form a Y shape, targets the lower traps and rotator cuff."},{"name":"Dumbbell Shrugs","sets":3,"reps":"15","rest":"45 sec","tempo":"1-1-1","rpe":6,"notes":"Finisher, straight up-and-down motion only."}]'::jsonb, '{"type":"Elliptical","duration":"12 min","intensity":"Moderate","targetHeartRateZone":"65-75% max HR"}'::jsonb, '["Cross-body shoulder stretch, 30 sec each side","Neck stretch, 20 sec each side"]'::jsonb, ARRAY['No heavy pressing today — this session is designed to add pure volume without adding to your joint fatigue.','Good option the day after a heavy chest or shoulder press session.','Keep rest periods short on purpose — this is about accumulated time under tension, not maximal loads.']::text[], ARRAY['Fat Loss','Hypertrophy','High Volume','Intermediate']::text[]),
('SHOULDERS_005', 'Shoulders - Stability & Rotator Cuff Health', 'Shoulders', 'Intermediate', 55, 420, ARRAY['Shoulders']::text[], ARRAY['Rotator Cuff','Traps','Core']::text[], ARRAY['Dumbbells','Cables','Resistance Bands']::text[], 'Gym', '["5 min bike, easy pace","Band pull-aparts, 2x15","Arm circles, 20 each direction","Band external rotations, 2x12 each side"]'::jsonb, '[{"name":"Landmine Press","sets":4,"reps":"8-10 each side","rest":"75 sec","tempo":"2-1-2","rpe":7,"notes":"Angled path is easier on the shoulder joint than a straight overhead press."},{"name":"Band External Rotation","sets":3,"reps":"15 each side","rest":"45 sec","tempo":"2-1-2","rpe":5,"notes":"Elbow pinned to your side, light resistance — this is rehab-style, not a strength exercise."},{"name":"Cable Face Pull","sets":3,"reps":"15","rest":"60 sec","tempo":"2-1-1","rpe":6,"notes":"Slightly higher pull angle than usual, elbows above shoulder height."},{"name":"Single-Arm Cable Lateral Raise","sets":3,"reps":"12 each side","rest":"60 sec","tempo":"2-1-1","rpe":6,"notes":"Isolates one side at a time to correct imbalances."},{"name":"Scapular Wall Slides","sets":2,"reps":"12","rest":"45 sec","tempo":"slow","rpe":5,"notes":"Back against a wall, slide arms up and down keeping contact the whole time."},{"name":"Kettlebell Overhead Carry","sets":2,"reps":"30 sec each side","rest":"60 sec","tempo":"walking","rpe":6,"notes":"Light weight, this is about control and stability, not load."}]'::jsonb, '{"type":"Incline treadmill walking","duration":"12 min","intensity":"Light","targetHeartRateZone":"55-65% max HR"}'::jsonb, '["Cross-body shoulder stretch, 30 sec each side","Doorway chest stretch, 30 sec each side","Neck stretch, 20 sec each side"]'::jsonb, ARRAY['This is a ''prehab'' session — the goal is shoulder longevity, not maximal load. Keep the weights honest and light.','Rotate this in every 2-3 weeks even if your shoulders feel fine — it''s cheaper than fixing an injury later.','If you feel any pinching pain (not just fatigue) on any movement, stop that exercise and swap it out.']::text[], ARRAY['Fat Loss','Intermediate','Free Weight','Machine Based']::text[]),
('ARMS_001', 'Arms - Biceps & Triceps Superset Blast', 'Arms', 'Intermediate', 55, 460, ARRAY['Biceps','Triceps']::text[], ARRAY['Forearms']::text[], ARRAY['Dumbbells','Cables','Barbell']::text[], 'Gym', '["5 min bike, easy pace","Arm circles, 20 each direction","Light band curls and pushdowns, 1x15 each"]'::jsonb, '[{"name":"Barbell Curl (superset with) / Close-Grip Bench Press","sets":4,"reps":"8-10 / 8-10","rest":"90 sec","tempo":"2-0-2","rpe":8,"notes":"Superset — no rest between the curl and the press, rest only after both are done."},{"name":"Hammer Curl (superset with) / Rope Pushdown","sets":3,"reps":"10-12 / 12-15","rest":"75 sec","tempo":"2-0-2","rpe":7,"notes":"Same superset structure — keep the pace brisk between the pair."},{"name":"Incline Dumbbell Curl (superset with) / Overhead Triceps Extension","sets":3,"reps":"10-12 / 10-12","rest":"75 sec","tempo":"2-0-2","rpe":7,"notes":"Full stretch on both movements at the bottom of each rep."},{"name":"Cable Curl (superset with) / Cable Kickback","sets":2,"reps":"15 / 15","rest":"60 sec","tempo":"2-0-2","rpe":7,"notes":"Finisher pair — light weight, full burn."}]'::jsonb, '{"type":"Rowing","duration":"10 min","intensity":"Moderate","targetHeartRateZone":"65-75% max HR"}'::jsonb, '["Biceps wall stretch, 30 sec each side","Overhead triceps stretch, 30 sec each side","Forearm stretch, 20 sec each side"]'::jsonb, ARRAY['Supersetting opposing muscle groups (biceps/triceps) lets one recover while the other works — efficient and effective.','Keep transitions between the paired exercises under 15 seconds to get the full conditioning benefit.','Arm pump will be intense by the end — that''s the intended stimulus for this session.']::text[], ARRAY['Fat Loss','Hypertrophy','High Volume','Intermediate','Free Weight']::text[]),
('ARMS_002', 'Arms - Strength-Focused Heavy Day', 'Arms', 'Intermediate', 60, 470, ARRAY['Biceps','Triceps']::text[], ARRAY['Forearms']::text[], ARRAY['Barbell','Dumbbells','Bench']::text[], 'Gym', '["5 min bike, easy pace","Arm circles, 20 each direction","Empty-bar curl and close-grip press, 1x10 each"]'::jsonb, '[{"name":"Barbell Curl","sets":4,"reps":"6-8","rest":"90 sec","tempo":"2-1-2","rpe":8,"notes":"Heaviest weight you can manage with strict form — no swinging."},{"name":"Close-Grip Bench Press","sets":4,"reps":"6-8","rest":"90 sec","tempo":"2-1-1","rpe":8,"notes":"Primary triceps mass-builder for the session."},{"name":"Weighted Dips","sets":3,"reps":"8-10","rest":"90 sec","tempo":"2-0-1","rpe":8,"notes":"Add weight via belt if bodyweight is manageable for 10+ reps."},{"name":"Incline Dumbbell Curl","sets":3,"reps":"8-10","rest":"75 sec","tempo":"2-1-2","rpe":7,"notes":"Second heaviest biceps movement — full stretch position."},{"name":"Skull Crushers","sets":3,"reps":"8-10","rest":"75 sec","tempo":"2-0-1","rpe":7,"notes":"EZ-bar preferred if available, easier on the wrists."}]'::jsonb, '{"type":"Cycling","duration":"10 min","intensity":"Light-Moderate","targetHeartRateZone":"60-70% max HR"}'::jsonb, '["Biceps wall stretch, 30 sec each side","Overhead triceps stretch, 30 sec each side"]'::jsonb, ARRAY['Strength-focused arm work builds the foundation that higher-rep pump work later just adds size on top of.','Elbow health matters long term — if close-grip bench bothers your elbows, widen the grip slightly.','Progress the load slowly here, roughly 2.5kg per side every couple of weeks once reps are solid.']::text[], ARRAY['Fat Loss','Strength','Intermediate','Free Weight','Compound Focus']::text[]),
('ARMS_003', 'Arms - Cable-Only Constant Tension', 'Arms', 'Intermediate', 50, 420, ARRAY['Biceps','Triceps']::text[], ARRAY['Forearms']::text[], ARRAY['Cables']::text[], 'Gym', '["5 min bike, easy pace","Light cable curls and pushdowns, 1x15 each"]'::jsonb, '[{"name":"Cable Curl (Straight Bar)","sets":4,"reps":"12-15","rest":"60 sec","tempo":"2-0-2","rpe":7,"notes":"Constant tension throughout, no dead spot like a free-weight curl has."},{"name":"Rope Triceps Pushdown","sets":4,"reps":"12-15","rest":"60 sec","tempo":"2-0-1","rpe":7,"notes":"Spread the rope apart at the bottom of every rep."},{"name":"Cable Hammer Curl (Rope)","sets":3,"reps":"12-15","rest":"60 sec","tempo":"2-0-2","rpe":7,"notes":"Neutral grip, targets the brachialis for arm thickness."},{"name":"Overhead Cable Triceps Extension","sets":3,"reps":"12-15","rest":"60 sec","tempo":"2-0-1","rpe":7,"notes":"Full stretch behind the head, elbows fixed."},{"name":"Single-Arm Cable Curl","sets":2,"reps":"12 each side","rest":"45 sec","tempo":"2-0-2","rpe":7,"notes":"Corrects any left/right imbalance from the bilateral work earlier."},{"name":"Single-Arm Cable Pushdown","sets":2,"reps":"12 each side","rest":"45 sec","tempo":"2-0-1","rpe":7,"notes":"Same unilateral logic, applied to triceps."}]'::jsonb, '{"type":"Elliptical","duration":"10 min","intensity":"Moderate","targetHeartRateZone":"65-75% max HR"}'::jsonb, '["Biceps wall stretch, 30 sec each side","Overhead triceps stretch, 30 sec each side","Forearm stretch, 20 sec each side"]'::jsonb, ARRAY['Cable work removes momentum from the equation entirely — every rep is honest tension.','Great low-fatigue option to slot in even on a day you''re feeling generally beat up elsewhere.','The whole session needs just one cable station if your gym is busy — efficient to squeeze in.']::text[], ARRAY['Fat Loss','Hypertrophy','Machine Based','Intermediate']::text[]),
('ARMS_004', 'Arms - Dumbbell 21s & Drop Sets', 'Arms', 'Intermediate', 50, 430, ARRAY['Biceps','Triceps']::text[], ARRAY['Forearms']::text[], ARRAY['Dumbbells','Bench']::text[], 'Gym', '["5 min bike, easy pace","Arm circles, 20 each direction","Light dumbbell curls, 1x15"]'::jsonb, '[{"name":"Dumbbell 21s Curl","sets":3,"reps":"7 bottom half + 7 top half + 7 full","rest":"90 sec","tempo":"controlled","rpe":8,"notes":"Classic burnout technique — expect serious biceps fatigue by the third set."},{"name":"Dumbbell Skull Crushers (Drop Set)","sets":3,"reps":"10 then drop 20% for 10 more","rest":"90 sec","tempo":"2-0-1","rpe":8,"notes":"Have a lighter pair of dumbbells ready to grab immediately after the first 10 reps."},{"name":"Incline Dumbbell Curl","sets":3,"reps":"10-12","rest":"75 sec","tempo":"2-1-2","rpe":7,"notes":"Full stretch position, controlled tempo."},{"name":"Dumbbell Kickback","sets":3,"reps":"12-15","rest":"60 sec","tempo":"2-1-1","rpe":6,"notes":"Torso hinged forward, upper arm parallel to the floor throughout."},{"name":"Zottman Curl","sets":2,"reps":"12","rest":"60 sec","tempo":"2-0-2","rpe":6,"notes":"Curl up palms-up, rotate, lower palms-down — trains biceps and forearms together."}]'::jsonb, '{"type":"Assault Bike","duration":"8 min","intensity":"Moderate","targetHeartRateZone":"65-75% max HR"}'::jsonb, '["Biceps wall stretch, 30 sec each side","Overhead triceps stretch, 30 sec each side"]'::jsonb, ARRAY['21s and drop sets are intensity techniques — use them sparingly (once every week or two) so they stay effective.','Expect noticeable next-day soreness after this session — plan an easier session or rest day after.','Have your second set of dumbbells staged next to you before starting the drop set so you don''t waste time hunting for them.']::text[], ARRAY['Fat Loss','Hypertrophy','High Volume','Intermediate','Free Weight']::text[]),
('ARMS_005', 'Arms - Forearm & Grip Emphasis', 'Arms', 'Intermediate', 50, 420, ARRAY['Biceps','Triceps','Forearms']::text[], ARRAY[]::text[], ARRAY['Dumbbells','Barbell','Cables']::text[], 'Gym', '["5 min bike, easy pace","Wrist circles, 15 each direction","Light dumbbell curls, 1x15"]'::jsonb, '[{"name":"Barbell Curl","sets":3,"reps":"10-12","rest":"75 sec","tempo":"2-0-2","rpe":7,"notes":"Standard biceps builder to open the session."},{"name":"Rope Pushdown","sets":3,"reps":"12-15","rest":"60 sec","tempo":"2-0-1","rpe":7,"notes":"Triceps counterpart to balance the session."},{"name":"Reverse Barbell Curl","sets":3,"reps":"10-12","rest":"60 sec","tempo":"2-0-2","rpe":7,"notes":"Overhand grip, heavily loads the forearm extensors."},{"name":"Wrist Curl","sets":3,"reps":"15","rest":"45 sec","tempo":"2-1-2","rpe":6,"notes":"Forearms resting on thighs or a bench, full range at the wrist only."},{"name":"Reverse Wrist Curl","sets":3,"reps":"15","rest":"45 sec","tempo":"2-1-2","rpe":6,"notes":"Same setup, palms facing down — targets the opposing forearm muscles."},{"name":"Farmer''s Carry","sets":3,"reps":"40 sec","rest":"60 sec","tempo":"walking","rpe":7,"notes":"Heavy dumbbells, walk tall with shoulders back — grip will be the limiting factor, not the legs."}]'::jsonb, '{"type":"Rowing","duration":"10 min","intensity":"Moderate","targetHeartRateZone":"65-75% max HR"}'::jsonb, '["Forearm stretch (flexors), 20 sec each side","Forearm stretch (extensors), 20 sec each side","Biceps wall stretch, 30 sec each side"]'::jsonb, ARRAY['Grip strength is a genuinely underrated carryover to every pulling lift in this whole library — deadlifts, rows, pull-ups.','Farmer''s carries are simple but brutal — start with a weight you can hold for the full 40 seconds without dropping it.','If your grip is a limiter on other sessions'' pulling movements, this workout directly addresses that.']::text[], ARRAY['Fat Loss','Strength','Intermediate','Free Weight']::text[]),
('CORE_ABS_001', 'Core & Abs - Weighted Strength Circuit', 'Core & Abs', 'Intermediate', 40, 320, ARRAY['Abs','Obliques']::text[], ARRAY['Lower Back','Hip Flexors']::text[], ARRAY['Dumbbells','Cables','Bodyweight']::text[], 'Gym', '["3 min brisk walk","Cat-cow, 8 reps","Dead bug, 2x8 each side"]'::jsonb, '[{"name":"Cable Crunch","sets":4,"reps":"12-15","rest":"60 sec","tempo":"2-1-2","rpe":7,"notes":"Kneel facing the cable, crunch from the ribs down toward the hips, not the neck."},{"name":"Hanging Leg Raise","sets":3,"reps":"10-12","rest":"60 sec","tempo":"2-0-2","rpe":8,"notes":"Control the descent — swinging turns this into momentum, not core work."},{"name":"Weighted Russian Twist","sets":3,"reps":"12 each side","rest":"60 sec","tempo":"2-0-2","rpe":7,"notes":"Plate or dumbbell held at the chest, rotate from the torso not just the arms."},{"name":"Ab Wheel Rollout","sets":3,"reps":"8-10","rest":"60 sec","tempo":"3-0-2","rpe":8,"notes":"From the knees, only go as far as you can maintain a flat lower back."},{"name":"Weighted Plank","sets":3,"reps":"40 sec","rest":"45 sec","tempo":"hold","rpe":7,"notes":"Small plate on the upper back for added load, keep hips level."}]'::jsonb, '{"type":"Rowing","duration":"8 min","intensity":"Moderate","targetHeartRateZone":"65-75% max HR"}'::jsonb, '["Cobra stretch, 30 sec","Child''s pose, 45 sec","Seated spinal twist, 20 sec each side"]'::jsonb, ARRAY['Weighted core work builds real strength, not just visible abs — this carries directly into your squat and deadlift bracing.','If the ab wheel is too advanced from the knees, regress to a shorter range of motion rather than skipping it.','Visible abs come from body fat percentage, not from ab exercises alone — this session builds the muscle underneath.']::text[], ARRAY['Fat Loss','Strength','Intermediate','Free Weight']::text[]),
('CORE_ABS_002', 'Core & Abs - Anti-Rotation & Stability', 'Core & Abs', 'Intermediate', 40, 300, ARRAY['Abs','Obliques']::text[], ARRAY['Lower Back']::text[], ARRAY['Cables','Dumbbells','Bodyweight']::text[], 'Gym', '["3 min brisk walk","Cat-cow, 8 reps","Bird dog, 2x8 each side"]'::jsonb, '[{"name":"Pallof Press","sets":4,"reps":"12 each side","rest":"45 sec","tempo":"2-1-2","rpe":6,"notes":"Cable at chest height, press straight out and resist the rotation pulling you sideways."},{"name":"Suitcase Carry","sets":3,"reps":"30 sec each side","rest":"60 sec","tempo":"walking","rpe":6,"notes":"Single heavy dumbbell, walk tall without leaning toward the loaded side."},{"name":"Renegade Row","sets":3,"reps":"8 each side","rest":"60 sec","tempo":"1-0-1","rpe":7,"notes":"Anti-rotation demand from the plank position is the main point, not the row itself."},{"name":"Side Plank","sets":3,"reps":"30 sec each side","rest":"45 sec","tempo":"hold","rpe":6,"notes":"Stack hips and shoulders, don''t let the hips sag toward the floor."},{"name":"Bird Dog","sets":3,"reps":"10 each side","rest":"45 sec","tempo":"2-1-2","rpe":5,"notes":"Extend opposite arm and leg, keep the lower back flat, no rocking."}]'::jsonb, '{"type":"Cycling","duration":"8 min","intensity":"Light-Moderate","targetHeartRateZone":"60-70% max HR"}'::jsonb, '["Seated spinal twist, 20 sec each side","Child''s pose, 45 sec"]'::jsonb, ARRAY['Anti-rotation training is what actually protects your spine during heavy squats and deadlifts — arguably more useful than crunches.','These movements look easy — they''re not. Resist the urge to add load before your form is airtight.','Great low-impact session to slot in on a day your joints need a break from heavier lifting.']::text[], ARRAY['Fat Loss','Intermediate','Free Weight','Machine Based']::text[]),
('CORE_ABS_003', 'Core & Abs - Bodyweight Burnout', 'Core & Abs', 'Intermediate', 35, 300, ARRAY['Abs','Obliques']::text[], ARRAY['Hip Flexors']::text[], ARRAY['Bodyweight']::text[], 'Gym', '["3 min jump rope or brisk walk","Cat-cow, 8 reps"]'::jsonb, '[{"name":"Bicycle Crunch","sets":3,"reps":"20 each side","rest":"45 sec","tempo":"controlled","rpe":7,"notes":"Slow and controlled beats fast and sloppy — full rotation each rep."},{"name":"Mountain Climbers","sets":3,"reps":"30 sec","rest":"45 sec","tempo":"fast","rpe":8,"notes":"Keep hips low and level, don''t let them pike up."},{"name":"Plank","sets":3,"reps":"45 sec","rest":"45 sec","tempo":"hold","rpe":7,"notes":"Straight line from shoulders to ankles, squeeze the glutes."},{"name":"Leg Raises","sets":3,"reps":"15","rest":"45 sec","tempo":"2-0-2","rpe":7,"notes":"Lower back pressed into the floor the whole time, don''t let it arch."},{"name":"Flutter Kicks","sets":3,"reps":"30 sec","rest":"45 sec","tempo":"fast","rpe":7,"notes":"Small, quick kicks, lower back stays glued to the floor."},{"name":"V-Ups","sets":2,"reps":"12","rest":"45 sec","tempo":"2-0-2","rpe":8,"notes":"Finisher — reach hands to feet at the top of each rep."}]'::jsonb, '{"type":"Elliptical","duration":"10 min","intensity":"Moderate","targetHeartRateZone":"65-75% max HR"}'::jsonb, '["Cobra stretch, 30 sec","Child''s pose, 45 sec","Seated spinal twist, 20 sec each side"]'::jsonb, ARRAY['No equipment needed — good session for a day the gym floor is packed or you''re pressed for time.','This is a metabolic burnout session as much as a strength one — expect your heart rate to climb.','Quality over speed on every movement — a controlled bicycle crunch beats a fast sloppy one.']::text[], ARRAY['Fat Loss','Bodyweight','Conditioning','Intermediate']::text[]),
('CORE_ABS_004', 'Core & Abs - Lower Back & Spinal Health', 'Core & Abs', 'Intermediate', 40, 290, ARRAY['Lower Back','Abs']::text[], ARRAY['Glutes']::text[], ARRAY['Bodyweight','Dumbbells','Machines']::text[], 'Gym', '["3 min brisk walk","Cat-cow, 8 reps","Pelvic tilts, 2x10"]'::jsonb, '[{"name":"Back Extension (45-Degree Bench)","sets":4,"reps":"12-15","rest":"60 sec","tempo":"2-1-2","rpe":7,"notes":"Hinge from the hips, squeeze glutes at the top — don''t hyperextend the lower back."},{"name":"Dead Bug","sets":3,"reps":"10 each side","rest":"45 sec","tempo":"2-1-2","rpe":6,"notes":"Lower back stays pressed into the floor the entire set."},{"name":"Bird Dog","sets":3,"reps":"10 each side","rest":"45 sec","tempo":"2-1-2","rpe":5,"notes":"Slow and controlled, no rocking side to side."},{"name":"Glute Bridge","sets":3,"reps":"15","rest":"45 sec","tempo":"1-1-1","rpe":6,"notes":"Squeeze glutes hard at the top, avoid over-arching the lower back."},{"name":"Superman Hold","sets":3,"reps":"20 sec","rest":"45 sec","tempo":"hold","rpe":6,"notes":"Lift chest and legs slightly, hold — a gentle way to strengthen the erectors."},{"name":"Plank","sets":2,"reps":"45 sec","rest":"45 sec","tempo":"hold","rpe":6,"notes":"Finisher, straight line, no sagging hips."}]'::jsonb, '{"type":"Incline treadmill walking","duration":"10 min","intensity":"Light","targetHeartRateZone":"55-65% max HR"}'::jsonb, '["Child''s pose, 60 sec","Knee-to-chest stretch, 30 sec each side","Cat-cow, 8 reps"]'::jsonb, ARRAY['This session is specifically designed to build a resilient lower back to support your heavier squat and deadlift days.','None of these movements should cause pain — mild fatigue is expected, sharp pain is not. Stop if you feel the latter.','A strong, well-conditioned lower back is one of the best injury-prevention investments you can make.']::text[], ARRAY['Fat Loss','Intermediate','Free Weight','Machine Based']::text[]),
('CORE_ABS_005', 'Core & Abs - Rotational Power & Obliques', 'Core & Abs', 'Intermediate', 40, 330, ARRAY['Obliques','Abs']::text[], ARRAY['Hip Flexors']::text[], ARRAY['Dumbbells','Cables','Kettlebell']::text[], 'Gym', '["3 min brisk walk","Torso rotations, 2x10 each side","Cat-cow, 8 reps"]'::jsonb, '[{"name":"Cable Woodchopper (High to Low)","sets":4,"reps":"12 each side","rest":"60 sec","tempo":"controlled","rpe":7,"notes":"Rotate from the torso and hips together, pivot the back foot."},{"name":"Russian Twist (Weighted)","sets":3,"reps":"15 each side","rest":"45 sec","tempo":"2-0-2","rpe":7,"notes":"Feet can stay down for more control if balance is limiting the load."},{"name":"Kettlebell Windmill","sets":3,"reps":"8 each side","rest":"60 sec","tempo":"slow","rpe":6,"notes":"Light kettlebell locked overhead, hinge at the hip while keeping eyes on the bell."},{"name":"Side Plank with Rotation","sets":3,"reps":"10 each side","rest":"45 sec","tempo":"controlled","rpe":7,"notes":"Thread the free arm under the torso then rotate it back up to the ceiling."},{"name":"Standing Oblique Crunch (Cable)","sets":2,"reps":"15 each side","rest":"45 sec","tempo":"2-0-2","rpe":6,"notes":"High pulley, crunch the elbow toward the same-side hip."}]'::jsonb, '{"type":"Rowing","duration":"8 min","intensity":"Moderate","targetHeartRateZone":"65-75% max HR"}'::jsonb, '["Seated spinal twist, 20 sec each side","Child''s pose, 45 sec"]'::jsonb, ARRAY['Rotational core strength carries over to almost every real-world movement — twisting, throwing, changing direction.','Control the rotation on woodchoppers — this isn''t about how fast you can whip the cable across.','Start light on kettlebell windmills — the shoulder position is unfamiliar for most lifters at first.']::text[], ARRAY['Fat Loss','Intermediate','Free Weight','Machine Based']::text[]),
('FULL_BODY_001', 'Full Body - Compound Strength Circuit', 'Full Body', 'Intermediate', 75, 650, ARRAY['Full Body']::text[], ARRAY['Core']::text[], ARRAY['Barbell','Dumbbells','Bench']::text[], 'Gym', '["5 min bike, easy pace","Bodyweight squats, 2x12","Arm circles, 20 each direction","Band pull-aparts, 2x15"]'::jsonb, '[{"name":"Barbell Back Squat","sets":4,"reps":"6-8","rest":"120 sec","tempo":"2-1-1","rpe":8,"notes":"Sets the tone for the session — biggest lift first while fresh."},{"name":"Barbell Bench Press","sets":4,"reps":"6-8","rest":"120 sec","tempo":"2-1-1","rpe":8,"notes":"Main upper-body pushing movement."},{"name":"Barbell Bent-Over Row","sets":3,"reps":"8-10","rest":"90 sec","tempo":"2-1-1","rpe":7,"notes":"Balances the pressing volume with pulling volume."},{"name":"Standing Overhead Press","sets":3,"reps":"8-10","rest":"90 sec","tempo":"2-1-1","rpe":7,"notes":"Full-body tension needed to stabilize the bar overhead."},{"name":"Romanian Deadlift","sets":3,"reps":"8-10","rest":"90 sec","tempo":"2-1-1","rpe":7,"notes":"Posterior chain finisher on the lower body."},{"name":"Plank","sets":2,"reps":"45 sec","rest":"45 sec","tempo":"hold","rpe":6,"notes":"Core finisher to close out the session."}]'::jsonb, '{"type":"Rowing","duration":"10 min","intensity":"Moderate","targetHeartRateZone":"65-75% max HR"}'::jsonb, '["Standing quad stretch, 30 sec each side","Doorway chest stretch, 30 sec each side","Lat stretch on rack, 30 sec each side"]'::jsonb, ARRAY['This is the highest total-body demand session in the library — make sure you''re well fed and rested beforehand.','The big five lifts here (squat, bench, row, press, RDL) cover almost every major muscle group in one session.','If total volume feels like too much on a given day, trim the accessory sets before trimming the compound lifts.']::text[], ARRAY['Fat Loss','Strength','Hypertrophy','Intermediate','Compound Focus','Free Weight']::text[]),
('FULL_BODY_002', 'Full Body - Dumbbell Only Session', 'Full Body', 'Intermediate', 65, 580, ARRAY['Full Body']::text[], ARRAY['Core']::text[], ARRAY['Dumbbells','Bench']::text[], 'Gym', '["5 min bike, easy pace","Bodyweight lunges, 2x10 each leg","Arm circles, 20 each direction"]'::jsonb, '[{"name":"Dumbbell Goblet Squat","sets":4,"reps":"10-12","rest":"90 sec","tempo":"2-0-1","rpe":7,"notes":"Heaviest dumbbell you can hold at the chest with good depth."},{"name":"Dumbbell Bench Press","sets":4,"reps":"10-12","rest":"90 sec","tempo":"2-1-2","rpe":7,"notes":"Full range of motion, control the descent."},{"name":"Dumbbell Bent-Over Row","sets":3,"reps":"10-12","rest":"75 sec","tempo":"2-1-1","rpe":7,"notes":"Flat back, pull to the lower ribs."},{"name":"Dumbbell Romanian Deadlift","sets":3,"reps":"10-12","rest":"75 sec","tempo":"2-1-1","rpe":7,"notes":"Soft knees, hinge at the hips, feel the hamstring stretch."},{"name":"Dumbbell Shoulder Press","sets":3,"reps":"10-12","rest":"75 sec","tempo":"2-1-2","rpe":7,"notes":"Seated or standing, either works."},{"name":"Renegade Row","sets":2,"reps":"8 each side","rest":"60 sec","tempo":"1-0-1","rpe":7,"notes":"Core and back finisher combined into one movement."}]'::jsonb, '{"type":"Cycling","duration":"10 min","intensity":"Moderate","targetHeartRateZone":"65-75% max HR"}'::jsonb, '["Standing quad stretch, 30 sec each side","Doorway chest stretch, 30 sec each side","Lat stretch on rack, 30 sec each side"]'::jsonb, ARRAY['This session works even on a busy gym day when the squat rack and bench are both taken — a dumbbell station is enough.','Great option for travel gyms with limited equipment too.','Keep dumbbell weight selection honest — the last 2-3 reps of every set should feel genuinely hard.']::text[], ARRAY['Fat Loss','Hypertrophy','Intermediate','Free Weight','Compound Focus']::text[]),
('FULL_BODY_003', 'Full Body - Functional Circuit', 'Full Body', 'Intermediate', 55, 540, ARRAY['Full Body']::text[], ARRAY['Core','Cardiovascular System']::text[], ARRAY['Kettlebell','Dumbbells','Bodyweight']::text[], 'Gym', '["5 min brisk walk or bike","Bodyweight squats, 2x12","Arm circles, 20 each direction"]'::jsonb, '[{"name":"Kettlebell Swing","sets":4,"reps":"15","rest":"60 sec","tempo":"explosive","rpe":7,"notes":"Hip-hinge power movement, not a squat — the kettlebell floats from hip drive."},{"name":"Goblet Squat to Press","sets":3,"reps":"10","rest":"75 sec","tempo":"controlled","rpe":7,"notes":"Combine a squat and an overhead press into one fluid movement."},{"name":"Dumbbell Thruster","sets":3,"reps":"10","rest":"75 sec","tempo":"controlled","rpe":8,"notes":"Front squat into a press — full body, high heart rate."},{"name":"Renegade Row to Push-Up","sets":3,"reps":"6 each side + 6 push-ups","rest":"75 sec","tempo":"controlled","rpe":7,"notes":"Combines pulling, anti-rotation, and pressing in one circuit round."},{"name":"Kettlebell Goblet Reverse Lunge","sets":2,"reps":"10 each leg","rest":"60 sec","tempo":"2-0-1","rpe":7,"notes":"Finisher — controlled pace even as fatigue sets in."}]'::jsonb, '{"type":"Assault Bike","duration":"8 min","intensity":"Moderate-High","targetHeartRateZone":"70-80% max HR"}'::jsonb, '["Standing quad stretch, 30 sec each side","Child''s pose, 45 sec","Doorway chest stretch, 30 sec each side"]'::jsonb, ARRAY['This session blends strength and conditioning — expect your heart rate to stay elevated throughout, not just during the cardio block.','Combination movements (squat-to-press, thrusters) demand more coordination — start lighter than your isolated lift numbers.','Great option when time is tight but you still want full-body coverage.']::text[], ARRAY['Fat Loss','Conditioning','Intermediate','Free Weight']::text[]),
('FULL_BODY_004', 'Full Body - Machine Circuit (Joint-Friendly)', 'Full Body', 'Intermediate', 65, 560, ARRAY['Full Body']::text[], ARRAY['Core']::text[], ARRAY['Machines','Cables']::text[], 'Gym', '["5 min bike, easy pace","Band pull-aparts, 2x15","Light machine leg press, 1x15"]'::jsonb, '[{"name":"Leg Press","sets":4,"reps":"10-12","rest":"90 sec","tempo":"2-1-2","rpe":7,"notes":"Lower-impact way to load the legs heavily."},{"name":"Machine Chest Press","sets":3,"reps":"10-12","rest":"75 sec","tempo":"2-1-2","rpe":7,"notes":"Fixed path takes stabilizer demand out of the equation."},{"name":"Seated Row Machine","sets":3,"reps":"10-12","rest":"75 sec","tempo":"2-1-2","rpe":7,"notes":"Pull with the elbows, squeeze the shoulder blades together."},{"name":"Machine Shoulder Press","sets":3,"reps":"10-12","rest":"75 sec","tempo":"2-1-2","rpe":7,"notes":"Joint-friendly overhead pressing option."},{"name":"Leg Curl (Machine)","sets":2,"reps":"12-15","rest":"60 sec","tempo":"2-1-2","rpe":6,"notes":"Hamstring finisher for the lower body."},{"name":"Cable Crunch","sets":2,"reps":"15","rest":"45 sec","tempo":"2-1-2","rpe":6,"notes":"Core finisher to close the session."}]'::jsonb, '{"type":"Elliptical","duration":"10 min","intensity":"Moderate","targetHeartRateZone":"65-75% max HR"}'::jsonb, '["Standing quad stretch, 30 sec each side","Doorway chest stretch, 30 sec each side","Lat stretch on rack, 30 sec each side"]'::jsonb, ARRAY['A good full-body option on weeks your joints need a break from barbell loading while still training hard.','Machines let you push each set closer to true failure safely — use that advantage.','This session pairs well as a lighter bookend the week after a heavy squat/bench/deadlift full-body day.']::text[], ARRAY['Fat Loss','Hypertrophy','Machine Based','Intermediate']::text[]),
('FULL_BODY_005', 'Full Body - Strength Endurance', 'Full Body', 'Intermediate', 60, 600, ARRAY['Full Body']::text[], ARRAY['Cardiovascular System','Core']::text[], ARRAY['Barbell','Dumbbells','Bodyweight']::text[], 'Gym', '["5 min bike, easy pace","Bodyweight squats, 2x12","Push-ups, 2x8"]'::jsonb, '[{"name":"Barbell Squat","sets":3,"reps":"12","rest":"75 sec","tempo":"controlled","rpe":7,"notes":"Higher reps, moderate weight — this session trains strength endurance, not max strength."},{"name":"Push-Ups","sets":3,"reps":"AMRAP","rest":"60 sec","tempo":"controlled","rpe":7,"notes":"Full range every rep, even as fatigue accumulates."},{"name":"Dumbbell Row","sets":3,"reps":"12 each side","rest":"60 sec","tempo":"controlled","rpe":7,"notes":"Keep the pace brisk between sides."},{"name":"Walking Lunges","sets":3,"reps":"12 each leg","rest":"60 sec","tempo":"controlled","rpe":7,"notes":"Continuous walking pattern, don''t rest mid-set."},{"name":"Dumbbell Shoulder Press","sets":3,"reps":"12","rest":"60 sec","tempo":"controlled","rpe":7,"notes":"Moderate weight, focus on maintaining pace over the set."},{"name":"Plank","sets":2,"reps":"45 sec","rest":"45 sec","tempo":"hold","rpe":6,"notes":"Core finisher."}]'::jsonb, '{"type":"Rowing","duration":"10 min","intensity":"Moderate-High","targetHeartRateZone":"70-80% max HR"}'::jsonb, '["Standing quad stretch, 30 sec each side","Child''s pose, 45 sec"]'::jsonb, ARRAY['Shorter rest periods here on purpose — this session blends strength work with a genuine conditioning effect.','Expect your heart rate to stay elevated between sets, unlike the heavier strength-focused sessions in this library.','A great fat-loss-oriented session when time is limited but intensity needs to stay high.']::text[], ARRAY['Fat Loss','Conditioning','Intermediate','High Volume','Free Weight']::text[]),
('CARDIO_CONDITIONING_001', 'Cardio & Conditioning - Steady-State Fat Loss', 'Cardio & Conditioning', 'Intermediate', 40, 420, ARRAY['Cardiovascular System']::text[], ARRAY['Legs']::text[], ARRAY['Treadmill']::text[], 'Gym', '["3 min flat treadmill walk to ease in","Ankle circles, 10 each direction"]'::jsonb, '[{"name":"Incline Treadmill Walk","sets":1,"reps":"35 min continuous","rest":"n/a","tempo":"steady","rpe":6,"notes":"6-8% incline, pace where you can talk in short sentences but not hold a full conversation."}]'::jsonb, '{"type":"Incline treadmill walking","duration":"35 min","intensity":"Moderate (Zone 2)","targetHeartRateZone":"60-70% max HR"}'::jsonb, '["3 min flat walk to bring heart rate down","Standing quad stretch, 30 sec each side","Calf stretch on wall, 30 sec each side"]'::jsonb, ARRAY['Zone 2 steady-state is one of the most sustainable fat-loss tools available — it''s genuinely low-fatigue relative to the calories burned.','This is a good session to pair with a rest day from lifting, or right after an upper-body session.','Track incline and speed weekly — small progressive increases here are real fitness gains.']::text[], ARRAY['Fat Loss','Conditioning','Intermediate']::text[]),
('CARDIO_CONDITIONING_002', 'Cardio & Conditioning - Rowing Intervals', 'Cardio & Conditioning', 'Intermediate', 35, 400, ARRAY['Cardiovascular System']::text[], ARRAY['Back','Legs']::text[], ARRAY['Rowing Machine']::text[], 'Gym', '["5 min easy-pace rowing","Dynamic torso rotations, 10 each side"]'::jsonb, '[{"name":"Rowing Intervals","sets":8,"reps":"500m fast + 90 sec easy row","rest":"n/a (built into interval)","tempo":"alternating","rpe":8,"notes":"Push a hard, consistent pace on each 500m — aim for a similar split time on every interval."}]'::jsonb, '{"type":"Rowing","duration":"25 min (intervals)","intensity":"High during work, Low during rest","targetHeartRateZone":"80-90% max HR during work intervals"}'::jsonb, '["5 min easy-pace rowing","Seated hamstring stretch, 30 sec each side","Lat stretch on rack, 30 sec each side"]'::jsonb, ARRAY['Focus on rowing technique before speed — legs drive first, then hips open, then arms pull.','If your split time drops noticeably after interval 5-6, you started too fast — pace yourself better next session.','Rowing is one of the few cardio modalities that also meaningfully trains the back — a nice bonus for a fat-loss-focused conditioning day.']::text[], ARRAY['Fat Loss','Conditioning','Intermediate']::text[]),
('CARDIO_CONDITIONING_003', 'Cardio & Conditioning - Bike Endurance Ride', 'Cardio & Conditioning', 'Intermediate', 45, 450, ARRAY['Cardiovascular System']::text[], ARRAY['Legs']::text[], ARRAY['Stationary Bike']::text[], 'Gym', '["5 min easy pedaling, low resistance"]'::jsonb, '[{"name":"Stationary Bike Ride","sets":1,"reps":"35 min continuous","rest":"n/a","tempo":"steady","rpe":6,"notes":"Moderate resistance, cadence around 80-90 RPM, consistent effort throughout."}]'::jsonb, '{"type":"Cycling","duration":"35 min","intensity":"Moderate (Zone 2)","targetHeartRateZone":"60-70% max HR"}'::jsonb, '["5 min easy pedaling to cool down","Standing quad stretch, 30 sec each side","Seated hamstring stretch, 30 sec each side"]'::jsonb, ARRAY['Cycling is one of the most joint-friendly cardio options available — a great choice if knees are feeling beat up from leg day.','Keep cadence steady rather than mashing hard at low RPM — smoother pedaling is easier on the knees long term.','This is a good low-fatigue conditioning session to schedule the day after a heavy leg workout.']::text[], ARRAY['Fat Loss','Conditioning','Intermediate']::text[]),
('CARDIO_CONDITIONING_004', 'Cardio & Conditioning - StairMaster Climb', 'Cardio & Conditioning', 'Intermediate', 30, 400, ARRAY['Cardiovascular System']::text[], ARRAY['Legs','Glutes']::text[], ARRAY['StairMaster']::text[], 'Gym', '["3 min slow-pace stair climbing"]'::jsonb, '[{"name":"StairMaster Steady Climb","sets":1,"reps":"25 min continuous","rest":"n/a","tempo":"steady","rpe":7,"notes":"Full foot on each step, upright posture — don''t lean on the handrails to take load off your legs."}]'::jsonb, '{"type":"StairMaster","duration":"25 min","intensity":"Moderate-High","targetHeartRateZone":"70-80% max HR"}'::jsonb, '["3 min slow-pace stepping to cool down","Standing quad stretch, 30 sec each side","Calf stretch on wall, 30 sec each side"]'::jsonb, ARRAY['The StairMaster is deceptively tough — 25 minutes here burns comparably to a much longer treadmill session.','Letting go of the handrails (even lightly resting fingertips only) roughly doubles the leg demand — build up to it.','Great glute-and-leg-friendly conditioning option that doubles as light active recovery for the upper body.']::text[], ARRAY['Fat Loss','Conditioning','Intermediate']::text[]),
('CARDIO_CONDITIONING_005', 'Cardio & Conditioning - Mixed Modality Endurance', 'Cardio & Conditioning', 'Intermediate', 40, 430, ARRAY['Cardiovascular System']::text[], ARRAY['Full Body']::text[], ARRAY['Treadmill','Rowing Machine','Stationary Bike']::text[], 'Gym', '["3 min easy walk"]'::jsonb, '[{"name":"Treadmill Block","sets":1,"reps":"12 min","rest":"n/a","tempo":"steady","rpe":6,"notes":"Incline walk or light jog, moderate steady effort."},{"name":"Rowing Block","sets":1,"reps":"12 min","rest":"n/a","tempo":"steady","rpe":6,"notes":"Smooth, consistent stroke rate, moderate effort."},{"name":"Bike Block","sets":1,"reps":"12 min","rest":"n/a","tempo":"steady","rpe":6,"notes":"Moderate resistance, steady cadence."}]'::jsonb, '{"type":"Rowing","duration":"36 min total across 3 machines","intensity":"Moderate","targetHeartRateZone":"65-75% max HR"}'::jsonb, '["3 min easy walk","Full-body light stretching, 5 min"]'::jsonb, ARRAY['Rotating machines keeps the same muscles from getting overly fatigued in one pattern while total cardio volume stays high.','This is a nice mental-variety session — 40 minutes on one machine can drag, 3 blocks of 12 rarely does.','Good option when you want a solid conditioning session without excessive impact on any single joint.']::text[], ARRAY['Fat Loss','Conditioning','Intermediate']::text[]),
('HIIT_001', 'HIIT - Bodyweight Tabata Circuit', 'HIIT', 'Intermediate', 25, 380, ARRAY['Full Body','Cardiovascular System']::text[], ARRAY['Core']::text[], ARRAY['Bodyweight']::text[], 'Gym', '["3 min jumping jacks and dynamic stretching","Bodyweight squats, 2x10"]'::jsonb, '[{"name":"Tabata Circuit: Squat Jumps / Push-Ups / Mountain Climbers / Burpees","sets":8,"reps":"20 sec work / 10 sec rest, rotating through the 4 movements","rest":"10 sec between rounds","tempo":"max effort","rpe":9,"notes":"Classic Tabata timing — 8 total rounds of 20 sec on, 10 sec off, cycling through all 4 exercises."}]'::jsonb, '{"type":"Bodyweight circuit (Tabata protocol)","duration":"16 min work","intensity":"Maximal","targetHeartRateZone":"85-95% max HR"}'::jsonb, '["3 min slow walk to bring heart rate down","Standing quad stretch, 30 sec each side","Child''s pose, 45 sec"]'::jsonb, ARRAY['True Tabata means genuinely maximal effort on the 20-second work windows — this should feel very hard by round 5-6.','At 108kg, burpees and squat jumps carry real impact load — land soft, and regress to step-back burpees if knees complain.','This is a short but brutal session — 16 minutes of actual work can rival 45 minutes of steady cardio in effect.']::text[], ARRAY['Fat Loss','Conditioning','Intermediate','Bodyweight']::text[]),
('HIIT_002', 'HIIT - Assault Bike Sprints', 'HIIT', 'Intermediate', 25, 400, ARRAY['Full Body','Cardiovascular System']::text[], ARRAY['Legs','Core']::text[], ARRAY['Assault Bike']::text[], 'Gym', '["5 min easy-pace assault bike"]'::jsonb, '[{"name":"Assault Bike Sprint Intervals","sets":10,"reps":"20 sec all-out sprint","rest":"40 sec easy pedaling","tempo":"max effort","rpe":9,"notes":"10 rounds of 20 sec max effort, 40 sec easy recovery pace — don''t fully stop during the rest."}]'::jsonb, '{"type":"Assault Bike","duration":"10 min work intervals","intensity":"Maximal during sprints","targetHeartRateZone":"85-95% max HR during sprints"}'::jsonb, '["3 min easy pedaling","Standing quad stretch, 30 sec each side","Seated hamstring stretch, 30 sec each side"]'::jsonb, ARRAY['The assault bike is unforgiving — pace the first 2-3 sprints slightly conservatively so you can hold effort through round 10.','This one hits both upper and lower body simultaneously, unlike a treadmill sprint — expect arms to fatigue too.','One of the most time-efficient conditioning sessions in this whole library — 10 minutes of real work.']::text[], ARRAY['Fat Loss','Conditioning','Intermediate']::text[]),
('HIIT_003', 'HIIT - Dumbbell Complex Circuit', 'HIIT', 'Intermediate', 30, 420, ARRAY['Full Body','Cardiovascular System']::text[], ARRAY['Core']::text[], ARRAY['Dumbbells']::text[], 'Gym', '["3 min jumping jacks","Bodyweight squats, 2x10","Arm circles, 20 each direction"]'::jsonb, '[{"name":"Dumbbell Complex: Deadlift + Row + Clean + Press + Squat","sets":6,"reps":"6 reps of each movement back-to-back, no rest between exercises","rest":"90 sec between full rounds","tempo":"controlled but brisk","rpe":8,"notes":"Same pair of dumbbells the whole complex — don''t set them down until all 5 movements are done."}]'::jsonb, '{"type":"Dumbbell complex (metabolic circuit)","duration":"18 min work","intensity":"High","targetHeartRateZone":"75-90% max HR"}'::jsonb, '["3 min easy walk","Doorway chest stretch, 30 sec each side","Standing quad stretch, 30 sec each side"]'::jsonb, ARRAY['Complexes build serious conditioning because the dumbbells never touch the floor — grip and heart rate both take a beating.','Choose a weight you could comfortably clean and press for 10+ reps on its own — the complex will make it feel much heavier by round 4.','Technique breaks down under fatigue faster in complexes than in isolated lifts — slow down rather than let form slip.']::text[], ARRAY['Fat Loss','Conditioning','Intermediate','Free Weight']::text[]),
('HIIT_004', 'HIIT - Kettlebell Swing Ladder', 'HIIT', 'Intermediate', 25, 390, ARRAY['Full Body','Cardiovascular System']::text[], ARRAY['Glutes','Core']::text[], ARRAY['Kettlebell']::text[], 'Gym', '["3 min brisk walk","Bodyweight hip hinges, 2x10","Light kettlebell swings, 1x10"]'::jsonb, '[{"name":"Kettlebell Swing Ladder (10-20-30-20-10)","sets":5,"reps":"10, 20, 30, 20, 10 reps ascending then descending","rest":"45 sec between ladder steps","tempo":"explosive","rpe":8,"notes":"Total of 90 swings across the ladder — power from the hips, not the arms or lower back."}]'::jsonb, '{"type":"Kettlebell swings (metabolic circuit)","duration":"15 min work","intensity":"High","targetHeartRateZone":"75-90% max HR"}'::jsonb, '["3 min easy walk","Figure-4 glute stretch, 30 sec each side","Seated hamstring stretch, 30 sec each side"]'::jsonb, ARRAY['The swing is a hip-hinge power movement — the kettlebell should feel like it''s floating up from hip drive, not being lifted by the arms.','By the 30-rep step your grip and lower back will both be tested — that''s the point of the ladder format.','If lower back rounds under fatigue on later sets, drop the kettlebell weight rather than push through bad form.']::text[], ARRAY['Fat Loss','Conditioning','Intermediate','Free Weight']::text[]),
('HIIT_005', 'HIIT - Sled Push & Sprint Intervals', 'HIIT', 'Intermediate', 30, 430, ARRAY['Full Body','Cardiovascular System']::text[], ARRAY['Legs','Core']::text[], ARRAY['Machines','Bodyweight']::text[], 'Gym', '["3 min brisk walk","Bodyweight squats, 2x10","Light sled push, 1x10m"]'::jsonb, '[{"name":"Sled Push (moderate load) + 20m Sprint (bodyweight or light bike sprint if no open floor)","sets":8,"reps":"20m sled push + 20m sprint","rest":"60 sec","tempo":"max effort","rpe":9,"notes":"If a sprint lane isn''t available, substitute a 20-second all-out effort on the assault bike after each sled push."}]'::jsonb, '{"type":"Sled push + sprint intervals","duration":"16 min work","intensity":"Maximal","targetHeartRateZone":"85-95% max HR"}'::jsonb, '["3 min easy walk","Standing quad stretch, 30 sec each side","Calf stretch on wall, 30 sec each side"]'::jsonb, ARRAY['This is one of the most demanding sessions in the library — genuinely elite-level conditioning work. Respect the recovery afterward.','Sled pushes are extremely joint-friendly for the load they provide since there''s no eccentric/lowering phase — knee-safe even at heavier loads.','If this leaves you unusually sore, swap it for a lighter HIIT variation next time and revisit once conditioning improves.']::text[], ARRAY['Fat Loss','Conditioning','Strength','Intermediate','Machine Based']::text[]),
('MOBILITY_RECOVERY_001', 'Mobility & Recovery - Full Body Flow', 'Mobility & Recovery', 'Intermediate', 35, 160, ARRAY['Joints','Connective Tissue']::text[], ARRAY['Full Body']::text[], ARRAY['Yoga Mat','Foam Roller']::text[], 'Gym', '["3 min easy walk to raise core temperature"]'::jsonb, '[{"name":"Foam Roll: Quads, Hamstrings, Lats, Upper Back","sets":1,"reps":"60 sec per area","rest":"n/a","tempo":"slow","rpe":3,"notes":"Slow, controlled rolling — pause on tender spots for 10-15 seconds rather than rolling faster."},{"name":"World''s Greatest Stretch","sets":2,"reps":"5 each side","rest":"n/a","tempo":"slow","rpe":3,"notes":"Full-body mobility flow hitting hips, hamstrings, and thoracic spine in one movement."},{"name":"Cat-Cow","sets":1,"reps":"10","rest":"n/a","tempo":"slow","rpe":2,"notes":"Sync the movement with your breath, full spinal range."},{"name":"90/90 Hip Switch","sets":2,"reps":"8 each side","rest":"n/a","tempo":"slow","rpe":3,"notes":"Great for hip internal/external rotation, often neglected in lifting programs."},{"name":"Thread the Needle","sets":2,"reps":"6 each side","rest":"n/a","tempo":"slow","rpe":3,"notes":"Thoracic spine rotation — helpful for shoulder and upper back mobility."}]'::jsonb, '{"type":"None — mobility focused session","duration":"n/a","intensity":"Very Light","targetHeartRateZone":"50-60% max HR"}'::jsonb, '["Seated forward fold, 60 sec","Deep breathing, 5 slow breaths"]'::jsonb, ARRAY['This session is a genuine training day, not a day off — mobility work directly improves your squat depth and overhead press range.','Nothing here should ever feel painful — mild tension and stretch is the target sensation.','Schedule this the day after your heaviest lifting session of the week to aid recovery.']::text[], ARRAY['Intermediate','Bodyweight']::text[]),
('MOBILITY_RECOVERY_002', 'Mobility & Recovery - Hip & Ankle Focus', 'Mobility & Recovery', 'Intermediate', 30, 140, ARRAY['Joints','Connective Tissue']::text[], ARRAY['Hips','Ankles']::text[], ARRAY['Yoga Mat','Foam Roller']::text[], 'Gym', '["3 min easy walk"]'::jsonb, '[{"name":"Foam Roll: Calves, Quads, IT Band","sets":1,"reps":"60 sec per area","rest":"n/a","tempo":"slow","rpe":3,"notes":"IT band rolling is uncomfortable for most people — go slow and reduce pressure if too intense."},{"name":"Ankle Dorsiflexion Rock","sets":2,"reps":"10 each side","rest":"n/a","tempo":"slow","rpe":3,"notes":"Kneeling position, rock knee over toes without heel lifting — directly improves squat depth."},{"name":"Deep Squat Hold","sets":3,"reps":"30 sec","rest":"30 sec","tempo":"hold","rpe":4,"notes":"Hold onto a rack or post for support if balance is limiting at first."},{"name":"Pigeon Pose","sets":2,"reps":"45 sec each side","rest":"n/a","tempo":"hold","rpe":3,"notes":"One of the best hip-opener stretches available — breathe deeply throughout."},{"name":"90/90 Hip Switch","sets":2,"reps":"8 each side","rest":"n/a","tempo":"slow","rpe":3,"notes":"Continues the hip mobility theme from earlier in the session."}]'::jsonb, '{"type":"None — mobility focused session","duration":"n/a","intensity":"Very Light","targetHeartRateZone":"50-60% max HR"}'::jsonb, '["Standing quad stretch, 30 sec each side","Deep breathing, 5 slow breaths"]'::jsonb, ARRAY['Limited ankle mobility is one of the most common (and fixable) causes of poor squat depth — this session directly targets that.','Hip mobility work pays off on deadlift setup and lunge/split squat stability too.','Consistency matters more than intensity here — 20 minutes twice a week beats one long session once a month.']::text[], ARRAY['Intermediate','Bodyweight']::text[]),
('MOBILITY_RECOVERY_003', 'Mobility & Recovery - Upper Body & Thoracic Spine', 'Mobility & Recovery', 'Intermediate', 30, 140, ARRAY['Joints','Connective Tissue']::text[], ARRAY['Shoulders','Upper Back']::text[], ARRAY['Yoga Mat','Foam Roller','Resistance Bands']::text[], 'Gym', '["3 min easy walk"]'::jsonb, '[{"name":"Foam Roll: Upper Back, Lats","sets":1,"reps":"60 sec per area","rest":"n/a","tempo":"slow","rpe":3,"notes":"Support your head with your hands while rolling the upper back."},{"name":"Thread the Needle","sets":2,"reps":"6 each side","rest":"n/a","tempo":"slow","rpe":3,"notes":"Thoracic rotation — most desk-bound lifters are noticeably restricted here."},{"name":"Band Shoulder Dislocates","sets":2,"reps":"10","rest":"n/a","tempo":"slow","rpe":4,"notes":"Wide grip on the band, move slowly through the full overhead range."},{"name":"Scapular Wall Slides","sets":2,"reps":"12","rest":"n/a","tempo":"slow","rpe":3,"notes":"Maintain contact with the wall throughout the whole movement."},{"name":"Doorway Chest Stretch","sets":2,"reps":"45 sec each side","rest":"n/a","tempo":"hold","rpe":3,"notes":"Great counter to hours spent in a pressing-dominant training pattern."}]'::jsonb, '{"type":"None — mobility focused session","duration":"n/a","intensity":"Very Light","targetHeartRateZone":"50-60% max HR"}'::jsonb, '["Child''s pose, 60 sec","Deep breathing, 5 slow breaths"]'::jsonb, ARRAY['Upper body mobility directly improves overhead press range and bench press bar path — this isn''t just ''flexibility for its own sake.''','Band shoulder dislocates should feel like a stretch, never a pinch — widen your grip if you feel pinching.','A great session to pair with a desk-heavy work day to counter hours of forward-rounded posture.']::text[], ARRAY['Intermediate','Bodyweight']::text[]),
('MOBILITY_RECOVERY_004', 'Mobility & Recovery - Yoga-Inspired Flow', 'Mobility & Recovery', 'Intermediate', 35, 170, ARRAY['Full Body','Connective Tissue']::text[], ARRAY[]::text[], ARRAY['Yoga Mat']::text[], 'Gym', '["2 min seated deep breathing"]'::jsonb, '[{"name":"Sun Salutation Flow","sets":3,"reps":"1 full flow","rest":"n/a","tempo":"slow, breath-synced","rpe":4,"notes":"Down dog, plank, cobra, forward fold, repeat — move with the breath, not against a clock."},{"name":"Warrior II Hold","sets":2,"reps":"30 sec each side","rest":"n/a","tempo":"hold","rpe":4,"notes":"Builds hip and leg mobility along with a bit of strength endurance."},{"name":"Pigeon Pose","sets":2,"reps":"45 sec each side","rest":"n/a","tempo":"hold","rpe":3,"notes":"Deep hip opener, breathe into any tightness rather than forcing the stretch."},{"name":"Seated Forward Fold","sets":2,"reps":"45 sec","rest":"n/a","tempo":"hold","rpe":3,"notes":"Hamstring and lower back release."},{"name":"Supine Spinal Twist","sets":2,"reps":"30 sec each side","rest":"n/a","tempo":"hold","rpe":2,"notes":"Gentle spinal decompression to finish."}]'::jsonb, '{"type":"None — mobility focused session","duration":"n/a","intensity":"Very Light","targetHeartRateZone":"50-60% max HR"}'::jsonb, '["Savasana (lying still), 3 min","Deep breathing, 5 slow breaths"]'::jsonb, ARRAY['This is as much about downregulating the nervous system as it is about flexibility — a good session for a genuinely tired week.','No need for prior yoga experience — move at your own pace and skip anything that feels sharp rather than stretchy.','Pairs well the day before a heavy squat or deadlift session to arrive fresher.']::text[], ARRAY['Intermediate','Bodyweight']::text[]),
('MOBILITY_RECOVERY_005', 'Mobility & Recovery - Lower Body Deep Stretch', 'Mobility & Recovery', 'Intermediate', 35, 160, ARRAY['Joints','Connective Tissue']::text[], ARRAY['Hips','Hamstrings','Calves']::text[], ARRAY['Yoga Mat','Foam Roller']::text[], 'Gym', '["3 min easy walk"]'::jsonb, '[{"name":"Foam Roll: Hamstrings, Quads, Glutes, Calves","sets":1,"reps":"60 sec per area","rest":"n/a","tempo":"slow","rpe":3,"notes":"Full lower-body rolling sweep — this session is dedicated entirely to leg recovery."},{"name":"Standing Quad Stretch","sets":2,"reps":"45 sec each side","rest":"n/a","tempo":"hold","rpe":3,"notes":"Hold onto something for balance, keep the knee pointed straight down."},{"name":"Seated Hamstring Stretch","sets":2,"reps":"45 sec each side","rest":"n/a","tempo":"hold","rpe":3,"notes":"Flat back, hinge from the hips rather than rounding the spine."},{"name":"Figure-4 Glute Stretch","sets":2,"reps":"45 sec each side","rest":"n/a","tempo":"hold","rpe":3,"notes":"Lying on the floor or a bench, whichever is more comfortable."},{"name":"Calf Stretch on Wall","sets":2,"reps":"30 sec each side","rest":"n/a","tempo":"hold","rpe":3,"notes":"Bent-knee variation afterward targets the soleus specifically."}]'::jsonb, '{"type":"None — mobility focused session","duration":"n/a","intensity":"Very Light","targetHeartRateZone":"50-60% max HR"}'::jsonb, '["Legs-up-the-wall, 3 min","Deep breathing, 5 slow breaths"]'::jsonb, ARRAY['Schedule this the day after your heaviest leg session — it directly speeds up recovery from squat and deadlift soreness.','Hold each stretch to a point of mild tension, never pain — breathe slowly and let the muscle release over time.','Legs-up-the-wall at the end is a simple, effective way to help with lower-leg swelling and circulation after heavy training.']::text[], ARRAY['Intermediate','Bodyweight']::text[]),
('ACTIVE_RECOVERY_001', 'Active Recovery - Easy Walk & Stretch', 'Active Recovery', 'Intermediate', 35, 210, ARRAY['Full Body']::text[], ARRAY['Cardiovascular System']::text[], ARRAY['Treadmill','Yoga Mat']::text[], 'Gym', '["2 min slow walk to ease in"]'::jsonb, '[{"name":"Flat Treadmill Walk","sets":1,"reps":"20 min","rest":"n/a","tempo":"easy, conversational pace","rpe":3,"notes":"You should be able to hold a full conversation comfortably the entire time."},{"name":"Full-Body Static Stretch Sequence","sets":1,"reps":"10 min","rest":"n/a","tempo":"slow","rpe":2,"notes":"Quads, hamstrings, chest, lats, shoulders — 45 sec each, whatever feels tightest that day."}]'::jsonb, '{"type":"Flat treadmill walking","duration":"20 min","intensity":"Very Light","targetHeartRateZone":"50-60% max HR"}'::jsonb, '["Deep breathing, 5 slow breaths"]'::jsonb, ARRAY['The whole point of active recovery is that it should feel easy — if you''re breathing hard, slow down.','Light movement genuinely speeds up recovery better than doing nothing at all, by promoting blood flow to fatigued muscles.','This is an ideal session the day after your toughest workout of the week, or on a day you''re feeling run down.']::text[], ARRAY['Intermediate','Bodyweight']::text[]),
('ACTIVE_RECOVERY_002', 'Active Recovery - Easy Bike Spin', 'Active Recovery', 'Intermediate', 30, 200, ARRAY['Full Body']::text[], ARRAY['Cardiovascular System','Legs']::text[], ARRAY['Stationary Bike']::text[], 'Gym', '["2 min very easy pedaling"]'::jsonb, '[{"name":"Easy Stationary Bike Spin","sets":1,"reps":"25 min","rest":"n/a","tempo":"very light resistance","rpe":3,"notes":"Low resistance, high cadence — this should feel almost too easy, and that''s correct."}]'::jsonb, '{"type":"Cycling","duration":"25 min","intensity":"Very Light","targetHeartRateZone":"50-60% max HR"}'::jsonb, '["Standing quad stretch, 30 sec each side","Seated hamstring stretch, 30 sec each side","Deep breathing, 5 slow breaths"]'::jsonb, ARRAY['Cycling at an easy spin is one of the gentlest ways to flush blood through fatigued legs after a heavy squat or deadlift day.','Resist the temptation to turn this into a real workout — the value here is specifically in the low intensity.','If you feel great and want to push harder, that''s a sign to schedule a real Cardio & Conditioning session instead of pushing this one further.']::text[], ARRAY['Intermediate']::text[]),
('ACTIVE_RECOVERY_003', 'Active Recovery - Pool Walk / Swim (Light)', 'Active Recovery', 'Intermediate', 30, 220, ARRAY['Full Body']::text[], ARRAY['Cardiovascular System']::text[], ARRAY['Bodyweight']::text[], 'Gym', '["2 min easy entry, gentle movement in the water"]'::jsonb, '[{"name":"Pool Walking / Easy Swimming","sets":1,"reps":"25 min","rest":"n/a","tempo":"easy, relaxed pace","rpe":3,"notes":"Water buoyancy takes significant load off the joints — great option if the gym floor has a pool available."}]'::jsonb, '{"type":"Pool walking or light swimming","duration":"25 min","intensity":"Very Light","targetHeartRateZone":"50-60% max HR"}'::jsonb, '["Gentle full-body stretching out of the water, 5 min","Deep breathing, 5 slow breaths"]'::jsonb, ARRAY['Water-based recovery is especially useful at higher bodyweight since it dramatically reduces joint compression.','This is a genuinely restorative session — don''t turn it into a lap-swimming workout.','If a pool isn''t available, swap this for the Easy Walk & Stretch or Easy Bike Spin variation instead.']::text[], ARRAY['Intermediate']::text[]),
('ACTIVE_RECOVERY_004', 'Active Recovery - Light Mobility Walk', 'Active Recovery', 'Intermediate', 35, 200, ARRAY['Full Body']::text[], ARRAY['Cardiovascular System']::text[], ARRAY['Treadmill','Yoga Mat']::text[], 'Gym', '["2 min easy walk"]'::jsonb, '[{"name":"Flat Treadmill Walk","sets":1,"reps":"15 min","rest":"n/a","tempo":"easy, conversational pace","rpe":3,"notes":"Relaxed pace throughout."},{"name":"World''s Greatest Stretch","sets":2,"reps":"5 each side","rest":"n/a","tempo":"slow","rpe":3,"notes":"Combines walking recovery with light mobility work."},{"name":"Cat-Cow","sets":1,"reps":"10","rest":"n/a","tempo":"slow","rpe":2,"notes":"Gentle spinal movement to finish."},{"name":"Deep Squat Hold","sets":2,"reps":"20 sec","rest":"20 sec","tempo":"hold","rpe":3,"notes":"Very light — just a gentle range-of-motion check-in, not a strength exercise today."}]'::jsonb, '{"type":"Flat treadmill walking","duration":"15 min","intensity":"Very Light","targetHeartRateZone":"50-60% max HR"}'::jsonb, '["Deep breathing, 5 slow breaths"]'::jsonb, ARRAY['This blends the two lightest categories in the library — walking and mobility — into one easy session.','A good choice specifically the day after a HIIT or sled push session when the whole body needs a break.','If you feel genuinely fatigued rather than just muscle-sore, consider a full rest day instead of even this session.']::text[], ARRAY['Intermediate','Bodyweight']::text[]),
('ACTIVE_RECOVERY_005', 'Active Recovery - Elliptical Easy Session', 'Active Recovery', 'Intermediate', 30, 210, ARRAY['Full Body']::text[], ARRAY['Cardiovascular System']::text[], ARRAY['Elliptical']::text[], 'Gym', '["2 min very easy pace"]'::jsonb, '[{"name":"Elliptical Easy Session","sets":1,"reps":"25 min","rest":"n/a","tempo":"low resistance, easy pace","rpe":3,"notes":"Zero-impact on the joints — a good option when even walking feels like too much that day."}]'::jsonb, '{"type":"Elliptical","duration":"25 min","intensity":"Very Light","targetHeartRateZone":"50-60% max HR"}'::jsonb, '["Full-body light stretching, 5 min","Deep breathing, 5 slow breaths"]'::jsonb, ARRAY['The elliptical''s zero-impact nature makes it one of the gentlest cardio options in the whole library.','This should feel refreshing, not depleting — if it doesn''t, drop the resistance further.','A solid rotation choice for active recovery days specifically when joints feel achy rather than muscles feeling sore.']::text[], ARRAY['Intermediate']::text[])
